const SVG_ID02 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Primary vs Secondary Identifiers</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">Interpol DVI standard · primary alone is sufficient · secondary only supportive</text>

<g data-node-id="pri-sec-key"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">🆔 IDENTIFIERS — Two Categories</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810">Per <strong>Interpol Disaster Victim Identification (DVI)</strong> protocol: <strong>PRIMARY identifiers</strong> are individually sufficient for positive identification; <strong>SECONDARY identifiers</strong> are only supportive and not stand-alone.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="primary-id"><rect class="body-white" x="60" y="240" width="730" height="380" rx="14" stroke="#15294F" stroke-width="3"/><path d="M 74,240 H 776 A 14,14 0 0 1 790,254 V 305 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gBlue)"/><text x="80" y="285" class="t-nlg">🏆 PRIMARY (3 only) — Stand-alone proof</text><text x="80" y="345" class="t-keylbl">1. FINGERPRINTS (Dactyloscopy)</text><text x="80" y="367" class="t-keyval">• Form in 2-5 month IUL · permanent · individual even in monozygotic twins</text><text x="80" y="388" class="t-keyval">• 16-20 matching points = positive ID</text><text x="80" y="420" class="t-keylbl">2. DENTAL RECORDS</text><text x="80" y="442" class="t-keyval">• Compared with antemortem dental chart, X-ray, restorations</text><text x="80" y="462" class="t-keyval">• Survives fire, putrefaction, skeletalisation</text><text x="80" y="495" class="t-keylbl">3. DNA PROFILE</text><text x="80" y="517" class="t-keyval">• Compare with reference sample (toothbrush, hairbrush) or relative</text><text x="80" y="537" class="t-keyval">• STR analysis · 13 CODIS loci · gold standard for decomposed / fragmented</text><text x="80" y="570" class="t-keylbl">★ Any ONE primary identifier = positive ID</text><text x="80" y="595" class="t-keyval" font-style="italic">DNA + dental + fingerprint = the "iron triangle" of forensic identification</text><circle class="ic" cx="770" cy="258" r="14"/><text class="t-info" x="770" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="secondary-id"><rect class="body-white" x="810" y="240" width="730" height="380" rx="14" stroke="#C58A3D" stroke-width="3"/><path d="M 824,240 H 1526 A 14,14 0 0 1 1540,254 V 305 H 810 V 254 A 14,14 0 0 1 824,240 Z" fill="url(#gOrange)"/><text x="830" y="285" class="t-nlg">📎 SECONDARY — Supportive Only</text><text x="830" y="335" class="t-keyval">• Visual recognition by relatives (unreliable in disasters)</text><text x="830" y="360" class="t-keyval">• Personal effects — clothes, jewellery, watch, ID card, mobile</text><text x="830" y="385" class="t-keyval">• Body modifications — <strong>tattoos · scars · piercings · birthmarks · moles</strong></text><text x="830" y="410" class="t-keyval">• Acquired deformities — old fractures, amputations, mal-union</text><text x="830" y="435" class="t-keyval">• Congenital deformities — cleft palate, polydactyly, claw hand</text><text x="830" y="460" class="t-keyval">• Occupation marks (callosities, dye stains, tailor\'s notch)</text><text x="830" y="485" class="t-keyval">• Anthropometric data (Bertillon — outdated)</text><text x="830" y="510" class="t-keyval">• Photographs · handwriting · speech recordings</text><text x="830" y="535" class="t-keyval">• Surgical implants — pacemaker, hip prosthesis (with serial number)</text><text x="830" y="565" class="t-keyval">• Medical conditions — DM, CHD, prior surgeries</text><text x="830" y="595" class="t-keyval" font-style="italic">★ Multiple secondaries together may suffice when primary unavailable</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="dvi-protocol"><rect x="60" y="640" width="1480" height="200" rx="14" fill="url(#gGreen)" filter="url(#cardShadow)"/><text x="800" y="680" class="t-nlg" text-anchor="middle">🌐 Interpol DVI — Disaster Victim Identification</text><text x="90" y="715" class="t-body"><strong>Standard for mass casualty (air crash, terror attack, tsunami):</strong></text><text x="90" y="740" class="t-body">• <strong>Pink form</strong> — postmortem (PM) data collected from body</text><text x="90" y="765" class="t-body">• <strong>Yellow form</strong> — antemortem (AM) data collected from family</text><text x="90" y="790" class="t-body">• Reconciliation phase compares PM and AM data → identification confirmed when ≥ 1 primary identifier or strong combination of secondaries matches</text><text x="90" y="815" class="t-body" font-style="italic">★ India used DVI protocol after 2004 tsunami, 26/11 Mumbai attacks, 2014 helicopter crash, etc.</text><circle class="ic" cx="1510" cy="658" r="14"/><text class="t-info" x="1510" y="664" text-anchor="middle">ⓘ</text></g>

<g data-node-id="dead-cat"><rect x="60" y="860" width="900" height="180" rx="14" fill="url(#gPurple)" filter="url(#cardShadow)"/><text x="510" y="900" class="t-nlg" text-anchor="middle">💀 Identification of Dead Body — by State</text><text x="90" y="935" class="t-body"><strong>Recently dead:</strong> visual recognition + fingerprints + personal effects easy · DNA from any tissue</text><text x="90" y="960" class="t-body"><strong>Decomposed:</strong> visual unreliable · use fingerprints (if hands preserved) · dental · DNA (deep tissue, bone marrow)</text><text x="90" y="985" class="t-body"><strong>Skeletal remains:</strong> bone DNA · dental records · <strong>superimposition</strong> · facial reconstruction · ossification/dentition for age</text><text x="90" y="1010" class="t-body" font-style="italic">★ Charred bodies: dental + DNA from femur bone marrow most reliable</text><circle class="ic" cx="940" cy="878" r="14"/><text class="t-info" x="940" y="884" text-anchor="middle">ⓘ</text></g>

<g data-node-id="superimposition"><rect x="980" y="860" width="560" height="180" rx="14" fill="url(#gGrey)" filter="url(#cardShadow)"/><text x="1260" y="900" class="t-nlg" text-anchor="middle">📷 Superimposition Technique</text><text x="1000" y="935" class="t-body"><strong>Method:</strong> Antemortem photograph of suspected</text><text x="1000" y="958" class="t-body">individual is superimposed on the skull image.</text><text x="1000" y="983" class="t-body"><strong>If anatomical landmarks (orbits, nasal aperture,</strong></text><text x="1000" y="1003" class="t-body">teeth, mandible) align → positive identification.</text><text x="1000" y="1028" class="t-body" font-style="italic">★ Used in Indira Gandhi assassins case</text><circle class="ic" cx="1520" cy="878" r="14"/><text class="t-info" x="1520" y="884" text-anchor="middle">ⓘ</text></g>
</svg>`;

const SVG_ID03 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Sex Determination — Living, Dead, Skeletal</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">3 levels of evidence · Barr / Davidson bodies · sub-pubic angle 85° (♀) vs 60° (♂)</text>

<g data-node-id="sex-evidence"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">⚥ EVIDENCE OF SEX — 3 Levels</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810"><strong>1. Presumptive</strong> — external appearance, clothes, hair, voice, body contour · <strong>2. Probable</strong> — secondary sex characteristics (breasts, genitals, hair distribution) · <strong>3. Positive</strong> — ovaries/testes OR Barr bodies / Davidson bodies / karyotyping.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="sex-physical"><rect class="body-white" x="60" y="240" width="730" height="320" rx="14"/><path d="M 74,240 H 776 A 14,14 0 0 1 790,254 V 295 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gBlue)"/><text x="80" y="280" class="t-nlg">📋 Male vs Female — Physical Features</text><text x="80" y="325" class="t-keylbl">Built · Height · Weight:</text><text x="290" y="325" class="t-keyval">♂ Muscular, taller, heavier</text><text x="80" y="350" class="t-keylbl">Scalp / facial hair:</text><text x="240" y="350" class="t-keyval">♂ Coarse, beard + moustache</text><text x="80" y="375" class="t-keylbl">Voice (post-puberty):</text><text x="270" y="375" class="t-keyval">♂ Hoarse · ♀ Soft</text><text x="80" y="400" class="t-keylbl">Body hair:</text><text x="180" y="400" class="t-keyval">♂ Chest / abdomen / limbs</text><text x="80" y="425" class="t-keylbl">Pubic hair pattern:</text><text x="240" y="425" class="t-keyval">♂ Diamond, extends to navel · ♀ Triangular</text><text x="80" y="450" class="t-keylbl">Breast:</text><text x="160" y="450" class="t-keyval">♂ Rudimentary · ♀ Developed</text><text x="80" y="475" class="t-keylbl">Thyroid cartilage angle:</text><text x="280" y="475" class="t-keyval">♂ &lt; 90° (prominent) · ♀ &gt; 120°</text><text x="80" y="500" class="t-keylbl">Shoulder vs hip:</text><text x="220" y="500" class="t-keyval">♂ Shoulder &gt; hip · ♀ Hip &gt; shoulder</text><text x="80" y="525" class="t-keylbl">Gluteal:</text><text x="160" y="525" class="t-keyval">♂ Flat · ♀ Full, roundish</text><circle class="ic" cx="770" cy="258" r="14"/><text class="t-info" x="770" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="sex-micro"><rect class="body-white" x="810" y="240" width="730" height="320" rx="14"/><path d="M 824,240 H 1526 A 14,14 0 0 1 1540,254 V 295 H 810 V 254 A 14,14 0 0 1 824,240 Z" fill="url(#gPurple)"/><text x="830" y="280" class="t-nlg">🔬 Microscopic / Chromosomal</text><text x="830" y="325" class="t-keylbl">BARR BODY (sex chromatin):</text><text x="830" y="347" class="t-keyval">• Inactivated X chromosome → basophilic, condensed mass</text><text x="830" y="367" class="t-keyval">at inner surface of nuclear membrane</text><text x="830" y="387" class="t-keyval">• Found in <strong>FEMALE</strong> somatic cells (buccal smear, skin, cartilage)</text><text x="830" y="407" class="t-keyval">• ABSENT in males → females are "chromatin positive"</text><text x="830" y="440" class="t-keylbl">DAVIDSON BODY (drumstick):</text><text x="830" y="462" class="t-keyval">• Additional lobe on female neutrophil nucleus (1.5 µm)</text><text x="830" y="482" class="t-keyval">• Need ≥ <strong>6% count</strong> on peripheral smear to confirm female sex</text><text x="830" y="502" class="t-keyval">• Stained with Leishman / Giemsa</text><text x="830" y="535" class="t-keylbl">KARYOTYPING + Y-chromosome detection</text><text x="830" y="557" class="t-keyval">Definitive — XX vs XY · cells grown in tissue culture · colchicine arrest</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="sex-pelvis"><rect x="60" y="580" width="1480" height="260" rx="14" fill="url(#gRed)" filter="url(#cardShadow)"/><text x="800" y="620" class="t-nlg" text-anchor="middle">🦴 PELVIS — Most Reliable Bone for Sex (Skeletal Remains)</text><text x="90" y="658" class="t-body"><strong>Sub-pubic angle:</strong> ♀ &gt; 90° (typically <strong>85°+ to 100°</strong>) · ♂ &lt; 90° (typically 50-60°) — ★ NEET-PG 2016 Q14: subpubic angle female = 85°</text><text x="90" y="685" class="t-body"><strong>Sciatic notch:</strong> ♀ wide and shallow (&gt; 60°) · ♂ narrow and deep</text><text x="90" y="710" class="t-body"><strong>Pelvic brim / inlet:</strong> ♀ oval, round, "gynaecoid" · ♂ heart-shaped, "android"</text><text x="90" y="735" class="t-body"><strong>Pelvic cavity:</strong> ♀ shallow, capacious · ♂ deep, narrow</text><text x="90" y="760" class="t-body"><strong>Sacrum:</strong> ♀ short, wide, less curved · ♂ long, narrow, more curved</text><text x="90" y="785" class="t-body"><strong>Obturator foramen:</strong> ♀ triangular · ♂ oval</text><text x="90" y="810" class="t-body"><strong>Acetabulum:</strong> ♀ smaller, faces forward · ♂ larger, faces laterally</text><circle class="ic" cx="1510" cy="598" r="14"/><text class="t-info" x="1510" y="604" text-anchor="middle">ⓘ</text></g>

<g data-node-id="sex-skull"><rect x="60" y="860" width="900" height="180" rx="14" fill="url(#gGrey)" filter="url(#cardShadow)"/><text x="510" y="900" class="t-nlg" text-anchor="middle">💀 Skull — Second-Best Bone for Sex</text><text x="90" y="935" class="t-body"><strong>Male skull:</strong> larger · heavier · supraorbital ridges prominent · forehead sloping · mastoid large</text><text x="90" y="960" class="t-body"><strong>Female skull:</strong> smaller · lighter · ridges smooth · forehead vertical · mastoid small</text><text x="90" y="985" class="t-body"><strong>Mandible:</strong> ♂ square chin, ramus angle &lt; 125° · ♀ rounded chin, ramus angle &gt; 125°</text><text x="90" y="1010" class="t-body" font-style="italic">Accuracy: pelvis 95% · skull 92% · combined 98%</text><circle class="ic" cx="940" cy="878" r="14"/><text class="t-info" x="940" y="884" text-anchor="middle">ⓘ</text></g>

<g data-node-id="sex-other"><rect x="980" y="860" width="560" height="180" rx="14" fill="url(#gOrange)" filter="url(#cardShadow)"/><text x="1260" y="900" class="t-nlg" text-anchor="middle">🦴 Other Skeletal Sex Markers</text><text x="1000" y="935" class="t-body"><strong>Sternum:</strong> ♂ length manubrium &gt; ½ body</text><text x="1000" y="958" class="t-body"><strong>Long bones:</strong> ♂ longer + thicker · ♀ smaller condyles</text><text x="1000" y="983" class="t-body"><strong>Femur head:</strong> ♂ ≥ 48 mm · ♀ ≤ 43 mm (diameter)</text><text x="1000" y="1008" class="t-body"><strong>Clavicle, scapula:</strong> ♂ longer + heavier</text><circle class="ic" cx="1520" cy="878" r="14"/><text class="t-info" x="1520" y="884" text-anchor="middle">ⓘ</text></g>
</svg>`;

const SVG_ID04 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Age Estimation — Overview &amp; Methods</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">4 categories · 1 yr / 7 yr / 12 yr / 18 yr / 21 yr legal milestones</text>

<g data-node-id="age-categories"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">📅 AGE ESTIMATION — 4 Categories of Subject</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810"><strong>1. Foetus</strong> — somite count, length-weight, morphology · <strong>2. Children &amp; adolescents</strong> — dentition + ossification + Tanner staging · <strong>3. Adults (&gt; 25 yr)</strong> — Gustafson\'s method + skeletal/skin changes · <strong>4. Dead body / skeletal remains</strong> — bones + teeth + secondary changes.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="age-foetus"><rect class="body-white" x="60" y="240" width="490" height="280" rx="14"/><path d="M 74,240 H 536 A 14,14 0 0 1 550,254 V 295 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gBlue)"/><text x="80" y="280" class="t-nlg">👶 Foetus Age Estimation</text><text x="80" y="325" class="t-keylbl">Up to 5 months:</text><text x="240" y="325" class="t-keyval">Length²= age in months</text><text x="100" y="345" class="t-keyval">(Haase formula)</text><text x="80" y="370" class="t-keylbl">After 5 months:</text><text x="220" y="370" class="t-keyval">Length / 5 = age in months</text><text x="100" y="390" class="t-keyval">(Haase formula)</text><text x="80" y="420" class="t-keylbl">Quickening:</text><text x="200" y="420" class="t-keyval">4 months IUL</text><text x="80" y="445" class="t-keylbl">Viability:</text><text x="180" y="445" class="t-keyval">7 months IUL</text><text x="80" y="470" class="t-keylbl">Crown-rump length:</text><text x="290" y="470" class="t-keyval">CRL · ultrasound</text><text x="80" y="500" class="t-keyval">Ossification centres also useful (see ID-06)</text><circle class="ic" cx="540" cy="258" r="14"/><text class="t-info" x="540" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="age-child"><rect class="body-white" x="570" y="240" width="490" height="280" rx="14" stroke="#3D8B5B" stroke-width="3"/><path d="M 584,240 H 1046 A 14,14 0 0 1 1060,254 V 295 H 570 V 254 A 14,14 0 0 1 584,240 Z" fill="url(#gGreen)"/><text x="590" y="280" class="t-nlg">🧒 Children — Primary Methods</text><text x="590" y="335" class="t-keyval">• <strong>DENTITION</strong> (eruption sequence + types) — see ID-05</text><text x="590" y="370" class="t-keyval">• <strong>OSSIFICATION centres</strong> (appearance + fusion) — see ID-06</text><text x="590" y="405" class="t-keyval">• <strong>Anthropometry</strong> — height/weight/head circumference</text><text x="590" y="430" class="t-keyval">• <strong>Tanner staging</strong> (sexual maturity rating):</text><text x="590" y="450" class="t-keyval">- T1 prepubertal → T5 adult genitalia/breast/pubic hair</text><text x="590" y="475" class="t-keyval">- Useful for 9-18 yr age</text><text x="590" y="500" class="t-keyval" font-style="italic">★ Combine dental + ossification for best accuracy in children</text><circle class="ic" cx="1050" cy="258" r="14"/><text class="t-info" x="1050" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="age-adult"><rect class="body-white" x="1080" y="240" width="460" height="280" rx="14"/><path d="M 1094,240 H 1526 A 14,14 0 0 1 1540,254 V 295 H 1080 V 254 A 14,14 0 0 1 1094,240 Z" fill="url(#gOrange)"/><text x="1090" y="280" class="t-nlg">👨 Adults &gt; 25 yr</text><text x="1090" y="335" class="t-keyval">• <strong>Gustafson\'s method</strong> (teeth) — 6 parameters:</text><text x="1090" y="357" class="t-keyval">attrition · periodontosis · secondary dentine ·</text><text x="1090" y="377" class="t-keyval">root resorption · cementum apposition · root transparency</text><text x="1090" y="412" class="t-keyval">• <strong>Skeletal changes</strong>:</text><text x="1090" y="432" class="t-keyval">- Lipping of lumbar vertebrae 40-50 yr</text><text x="1090" y="452" class="t-keyval">- Calcification of thyroid / hyoid 40+ yr</text><text x="1090" y="472" class="t-keyval">- Xiphoid-sternum fusion 40 yr · manubrium-body 60 yr</text><text x="1090" y="497" class="t-keyval">• Skin: wrinkles · arcus senilis · graying · baldness</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="age-legal"><rect x="60" y="540" width="1480" height="380" rx="14" fill="url(#gGrey)" filter="url(#cardShadow)"/><text x="800" y="580" class="t-nlg" text-anchor="middle">⚖️ Medicolegal Importance of Different Ages (Key Milestones)</text><text x="90" y="615" class="t-body"><strong>4 mo IUL</strong> — quickening · <strong>7 mo IUL</strong> — viability · <strong>&lt; 1 yr</strong> — killing = infanticide</text><text x="90" y="640" class="t-body"><strong>&lt; 7 yr</strong> — NO criminal responsibility (IPC 82 / BNS equivalent) ★</text><text x="90" y="665" class="t-body"><strong>7-12 yr</strong> — limited criminal responsibility IF child has sufficient maturity (IPC 83) ★</text><text x="90" y="690" class="t-body"><strong>&lt; 12 yr</strong> — cannot give consent for medical examination (IPC 89 / BNS) · oath not necessary in court</text><text x="90" y="715" class="t-body"><strong>&lt; 14 yr</strong> — cannot be employed in factories (Indian Factories Act 1948)</text><text x="90" y="740" class="t-body"><strong>&lt; 15 yr</strong> — sexual intercourse with wife &lt; 15 yr = punishable rape</text><text x="90" y="765" class="t-body"><strong>&lt; 18 yr (female)</strong> — taking from guardianship = kidnapping · is a "juvenile" under JJ Act 2015</text><text x="90" y="790" class="t-body"><strong>18 yr</strong> — attainment of majority · minimum marriage age (girls) · voting · consent age</text><text x="90" y="815" class="t-body"><strong>21 yr</strong> — minimum marriage age (boys) · attainment of majority under court guardianship</text><text x="90" y="840" class="t-body"><strong>25 yr</strong> — State Assembly election candidate · third molar erupts (max)</text><text x="90" y="865" class="t-body"><strong>30 yr</strong> — Parliament candidate · <strong>35 yr</strong> — President / VP / Governor candidate</text><text x="90" y="890" class="t-body"><strong>60-65 yr</strong> — government retirement · senior citizen status</text><circle class="ic" cx="1510" cy="558" r="14"/><text class="t-info" x="1510" y="564" text-anchor="middle">ⓘ</text></g>

<rect x="60" y="940" width="1480" height="60" rx="10" fill="url(#gOrange)"/><text x="800" y="978" font-family="Inter,system-ui,sans-serif" font-size="13.5" font-weight="700" fill="white" text-anchor="middle">🎯 Foetus = Haase · Children = dentition + ossification · Adult = Gustafson + skeletal · Skeletal = bone fusion + teeth</text>

<rect x="60" y="1020" width="1480" height="40" rx="10" fill="url(#gBlue)"/><text x="800" y="1048" font-family="Inter,system-ui,sans-serif" font-size="13" font-weight="700" fill="white" text-anchor="middle">⭐ NEET-PG 2016 Q10 — Person declared dead after 7 yrs (Indian Evidence Act / BSA) — civil presumption</text>
</svg>`;

const SVG_ID05 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Dentition — Primary &amp; Permanent · Eruption · Gustafson</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">20 milk teeth + 32 permanent · LOWER CENTRAL incisor erupts FIRST at 6 months ★</text>

<g data-node-id="teeth-overview"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">🦷 DENTITION — Forensic Foundation</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810"><strong>Primary (temporary / milk / deciduous):</strong> 20 teeth — 8 incisors + 4 canines + 8 molars. <strong>Permanent:</strong> 32 teeth — 8 incisors + 4 canines + 8 premolars + 12 molars. Eruption sequence is highly age-specific.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="primary-teeth"><rect class="body-white" x="60" y="240" width="730" height="320" rx="14" stroke="#3D8B5B" stroke-width="3"/><path d="M 74,240 H 776 A 14,14 0 0 1 790,254 V 295 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gGreen)"/><text x="80" y="280" class="t-nlg">🦷 PRIMARY (Milk / Deciduous) — 20 teeth</text><text x="80" y="325" class="t-keylbl">Composition (per jaw — 10 teeth):</text><text x="80" y="345" class="t-keyval">2 incisors + 1 canine + 2 molars in each half (×4 halves = 20)</text><text x="80" y="375" class="t-keylbl">★ Eruption Sequence (memorise) ★</text><text x="80" y="397" class="t-keyval">• <strong>Lower central incisor</strong> — 6-8 mo ← FIRST! ★</text><text x="80" y="417" class="t-keyval">• Upper central incisor — 7-9 mo</text><text x="80" y="437" class="t-keyval">• Upper lateral incisor — 8-10 mo</text><text x="80" y="457" class="t-keyval">• Lower lateral incisor — 10-12 mo</text><text x="80" y="477" class="t-keyval">• 1st molar — 12-14 mo (1 yr)</text><text x="80" y="497" class="t-keyval">• Canine — 18 mo (1.5 yr)</text><text x="80" y="517" class="t-keyval">• 2nd molar — 24 mo (2 yr)</text><text x="80" y="545" class="t-keyval" font-style="italic">★ "Half-year rule": add 6 months to type → period of eruption</text><circle class="ic" cx="770" cy="258" r="14"/><text class="t-info" x="770" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="permanent-teeth"><rect class="body-white" x="810" y="240" width="730" height="320" rx="14" stroke="#15294F" stroke-width="3"/><path d="M 824,240 H 1526 A 14,14 0 0 1 1540,254 V 295 H 810 V 254 A 14,14 0 0 1 824,240 Z" fill="url(#gBlue)"/><text x="830" y="280" class="t-nlg">🦷 PERMANENT — 32 teeth</text><text x="830" y="325" class="t-keylbl">Composition (per jaw — 16 teeth):</text><text x="830" y="345" class="t-keyval">2 incisors + 1 canine + 2 premolars + 3 molars per half (×4 = 32)</text><text x="830" y="375" class="t-keylbl">★ Eruption Sequence:</text><text x="830" y="397" class="t-keyval">• 1st molar — <strong>6 yr</strong> (★ first permanent tooth)</text><text x="830" y="417" class="t-keyval">• Central incisor — 7-8 yr</text><text x="830" y="437" class="t-keyval">• Lateral incisor — 8-9 yr</text><text x="830" y="457" class="t-keyval">• 1st premolar — 9-10 yr</text><text x="830" y="477" class="t-keyval">• 2nd premolar — 10-11 yr</text><text x="830" y="497" class="t-keyval">• Canine — 11-12 yr</text><text x="830" y="517" class="t-keyval">• 2nd molar — 12-14 yr · <strong>3rd molar (wisdom)</strong> — 17-25 yr</text><text x="830" y="545" class="t-keyval" font-style="italic">★ Females erupt slightly earlier than males</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="replacement"><rect x="60" y="580" width="1480" height="160" rx="14" fill="url(#gOrange)" filter="url(#cardShadow)"/><text x="800" y="620" class="t-nlg" text-anchor="middle">🔄 Mixed Dentition (6-12 yr) — Replacement Rules</text><text x="90" y="655" class="t-body">• <strong>Primary incisors + canines</strong> are replaced by <strong>PERMANENT incisors + canines</strong></text><text x="90" y="680" class="t-body">• <strong>Primary molars</strong> are replaced by <strong>PERMANENT PREMOLARS</strong> (not molars!)</text><text x="90" y="705" class="t-body">• 6 yr: first permanent molars erupt BEHIND the 2nd primary molar (no primary tooth lost)</text><text x="90" y="730" class="t-body" font-style="italic">★ Most commonly absent permanent tooth = 3rd molar (wisdom) · followed by upper lateral incisor</text><circle class="ic" cx="1510" cy="598" r="14"/><text class="t-info" x="1510" y="604" text-anchor="middle">ⓘ</text></g>

<g data-node-id="gustafson"><rect x="60" y="760" width="900" height="260" rx="14" fill="url(#gPurple)" filter="url(#cardShadow)"/><text x="510" y="800" class="t-nlg" text-anchor="middle">📐 Gustafson\'s Method (Adults &gt; 25 yr) ★</text><text x="90" y="835" class="t-body"><strong>6 parameters in extracted tooth — each scored 0-3:</strong></text><text x="90" y="860" class="t-body"><strong>1. Attrition (A)</strong> — wear on masticating surface</text><text x="90" y="880" class="t-body"><strong>2. Periodontosis (P)</strong> — exposure of root from gum recession</text><text x="90" y="900" class="t-body"><strong>3. Secondary dentine (S)</strong> — deposition in pulp cavity</text><text x="90" y="920" class="t-body"><strong>4. Root resorption (R)</strong> — decay/resorption of root</text><text x="90" y="940" class="t-body"><strong>5. Cementum apposition (C)</strong> — deposition increases with age</text><text x="90" y="960" class="t-body"><strong>6. Root transparency (T)</strong> — rarefaction of dentine — ★ SINGLE most important parameter</text><text x="90" y="990" class="t-body" font-style="italic">Formula: A + P + S + R + C + T = points → age</text><circle class="ic" cx="940" cy="778" r="14"/><text class="t-info" x="940" y="784" text-anchor="middle">ⓘ</text></g>

<g data-node-id="dental-other"><rect x="980" y="760" width="560" height="260" rx="14" fill="url(#gRed)" filter="url(#cardShadow)"/><text x="1260" y="800" class="t-nlg" text-anchor="middle">🩺 Other Age-from-Teeth Methods</text><text x="1000" y="835" class="t-body"><strong>Miles method:</strong> Root translucency alone</text><text x="1000" y="860" class="t-body"><strong>Biochemical:</strong> Aspartic acid racemisation</text><text x="1000" y="880" class="t-body">(Levo → Dextro conversion with age)</text><text x="1000" y="905" class="t-body"><strong>Fluorescence:</strong> Kvaal 1989 — dentine + cementum</text><text x="1000" y="930" class="t-body"><strong>Radiographic:</strong> Pulp/crown ratio decrease</text><text x="1000" y="955" class="t-body"><strong>Boyde\'s method:</strong> Neonatal line in enamel</text><text x="1000" y="980" class="t-body">— at birth · separates pre- from postnatal enamel</text><text x="1000" y="1005" class="t-body" font-style="italic">★ Hutchinson teeth = congenital syphilis (notched incisors)</text><circle class="ic" cx="1520" cy="778" r="14"/><text class="t-info" x="1520" y="784" text-anchor="middle">ⓘ</text></g>

<rect x="60" y="1040" width="1480" height="40" rx="10" fill="url(#gBlue)"/><text x="800" y="1068" font-family="Inter,system-ui,sans-serif" font-size="13" font-weight="700" fill="white" text-anchor="middle">⭐ NEET-PG 2016 Q15 — First incisor to erupt = LOWER CENTRAL · Q16 — First milk tooth at 6 months</text>
</svg>`;

const SVG_ID06 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Ossification Centres — Forensic Key Dates</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">A = appearance · F = fusion · scaphoid 4-6 yrs · pisiform 9-12 yrs ★</text>

<g data-node-id="ossif-overview"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">🦴 OSSIFICATION CENTRES — Age Estimation</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810">Bones develop from one or more <strong>OSSIFICATION CENTRES</strong> at characteristic ages. <strong>X-ray of wrist + elbow + shoulder</strong> shows fusion pattern → reliable age estimation in adolescents (8-25 yr). Females ossify ~ 1-2 yr earlier than males.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="carpal"><rect class="body-white" x="60" y="240" width="490" height="380" rx="14" stroke="#15294F" stroke-width="3"/><path d="M 74,240 H 536 A 14,14 0 0 1 550,254 V 295 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gBlue)"/><text x="80" y="280" class="t-nlg">✋ CARPAL Bones (X-ray of wrist)</text><text x="80" y="325" class="t-keylbl">★ Sequence of appearance ★</text><text x="80" y="347" class="t-keyval">1. <strong>Capitate</strong> — 1-3 mo</text><text x="80" y="367" class="t-keyval">2. <strong>Hamate</strong> — 2-4 mo</text><text x="80" y="387" class="t-keyval">3. <strong>Triquetral</strong> — 2-3 yr</text><text x="80" y="407" class="t-keyval">4. <strong>Lunate</strong> — 3-5 yr</text><text x="80" y="427" class="t-keyval">5. <strong>Trapezium</strong> — 4-6 yr</text><text x="80" y="447" class="t-keyval">6. <strong>Trapezoid</strong> — 4-7 yr</text><text x="80" y="467" class="t-keyval">7. <strong>SCAPHOID — 4-7 yr (NEET-PG 2016 Q13) ★</strong></text><text x="80" y="487" class="t-keyval">8. <strong>PISIFORM — 9-12 yr ★ LAST</strong></text><text x="80" y="517" class="t-keylbl">Mnemonic: "Come Here To Take Tea Soup Please"</text><text x="80" y="540" class="t-keyval">(Capitate-Hamate-Triquetral-Trapezium-Trapezoid-Scaphoid-Pisiform; Lunate fits in)</text><text x="80" y="570" class="t-keyval" font-style="italic">★ Pisiform = unique — sesamoid bone, last to ossify</text><circle class="ic" cx="540" cy="258" r="14"/><text class="t-info" x="540" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="long-bones"><rect class="body-white" x="570" y="240" width="490" height="380" rx="14"/><path d="M 584,240 H 1046 A 14,14 0 0 1 1060,254 V 295 H 570 V 254 A 14,14 0 0 1 584,240 Z" fill="url(#gGreen)"/><text x="590" y="280" class="t-nlg">🦴 Long Bones — Key Fusion Dates</text><text x="590" y="325" class="t-keylbl">Femur head:</text><text x="710" y="325" class="t-keyval">F 14-15 yr (♀), 16-17 yr (♂)</text><text x="590" y="350" class="t-keylbl">Greater trochanter:</text><text x="770" y="350" class="t-keyval">F 14 yr (♀), 17 yr (♂)</text><text x="590" y="375" class="t-keylbl">Distal femur:</text><text x="730" y="375" class="t-keyval">A before birth · F 14-17 yr</text><text x="590" y="400" class="t-keylbl">Proximal tibia:</text><text x="730" y="400" class="t-keyval">A before birth · F 14-17 yr</text><text x="590" y="425" class="t-keylbl">Distal radius/ulna:</text><text x="770" y="425" class="t-keyval">F 17-19 yr (♀), 19-20 yr (♂)</text><text x="590" y="450" class="t-keylbl">Iliac crest:</text><text x="690" y="450" class="t-keyval">F 17-19 yr (♀), 19-20 yr (♂)</text><text x="590" y="475" class="t-keylbl">Clavicle (medial):</text><text x="770" y="475" class="t-keyval">F 20-22 yr (♀ &amp; ♂) ★ last to fuse</text><text x="590" y="510" class="t-keylbl">★ TRIRADIATE cartilage of acetabulum:</text><text x="590" y="530" class="t-keyval">disappears 13-14 yr (♀), 15-16 yr (♂)</text><text x="590" y="560" class="t-keylbl">★ HIP BONE: ischio-pubic fusion 8.5 yr</text><text x="590" y="585" class="t-keyval" font-style="italic">★ Females fuse ~ 1-2 yr earlier than males</text><circle class="ic" cx="1050" cy="258" r="14"/><text class="t-info" x="1050" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="tarsals"><rect class="body-white" x="1080" y="240" width="460" height="380" rx="14"/><path d="M 1094,240 H 1526 A 14,14 0 0 1 1540,254 V 295 H 1080 V 254 A 14,14 0 0 1 1094,240 Z" fill="url(#gOrange)"/><text x="1090" y="280" class="t-nlg">🦶 TARSAL Bones (Foot)</text><text x="1090" y="325" class="t-keylbl">★ AT BIRTH:</text><text x="1090" y="347" class="t-keyval">• Calcaneum · Talus · Cuboid</text><text x="1090" y="370" class="t-keyval">(these three appear in utero — proves</text><text x="1090" y="390" class="t-keyval">live birth or near-term foetus)</text><text x="1090" y="420" class="t-keylbl">Other tarsals:</text><text x="1090" y="440" class="t-keyval">• Cuneiforms — 1-4 yr</text><text x="1090" y="460" class="t-keyval">• Navicular — 1-4 yr</text><text x="1090" y="495" class="t-keylbl">Other forensic landmarks:</text><text x="1090" y="517" class="t-keyval">• <strong>Distal end of femur</strong> ossifies before birth</text><text x="1090" y="537" class="t-keyval">→ indicates full-term infant ★</text><text x="1090" y="565" class="t-keyval">• <strong>Patella</strong> — 3-7 yr</text><text x="1090" y="585" class="t-keyval">• <strong>Hyoid</strong> — body before birth · greater horn 1-2 yr · fuses 40-50 yr</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="ossif-skull"><rect x="60" y="640" width="900" height="200" rx="14" fill="url(#gPurple)" filter="url(#cardShadow)"/><text x="510" y="680" class="t-nlg" text-anchor="middle">💀 Skull Sutures — Closure</text><text x="90" y="715" class="t-body"><strong>Anterior fontanelle</strong> — closes 18-24 months (~ 2 yr)</text><text x="90" y="740" class="t-body"><strong>Posterior fontanelle</strong> — closes 2-3 months</text><text x="90" y="765" class="t-body"><strong>Metopic suture</strong> (mid-frontal) — closes 3-8 yr (some remain open as "metopism")</text><text x="90" y="790" class="t-body"><strong>Sagittal suture</strong> — closes 30-40 yr · <strong>Coronal</strong> — 38-50 yr · <strong>Lambdoid</strong> — 45-50 yr</text><text x="90" y="815" class="t-body" font-style="italic">★ Skull suture closure is variable — gives only rough age estimate ± 5-10 yr in adults</text><circle class="ic" cx="940" cy="658" r="14"/><text class="t-info" x="940" y="664" text-anchor="middle">ⓘ</text></g>

<g data-node-id="sternum"><rect x="980" y="640" width="560" height="200" rx="14" fill="url(#gRed)" filter="url(#cardShadow)"/><text x="1260" y="680" class="t-nlg" text-anchor="middle">🦴 Sternum + Vertebrae</text><text x="1000" y="715" class="t-body"><strong>Sternum:</strong> Manubrium ossifies in utero</text><text x="1000" y="740" class="t-body">Body segments fuse 14-25 yr</text><text x="1000" y="763" class="t-body"><strong>Xiphoid-sternum</strong> fusion: ~ 40 yr</text><text x="1000" y="783" class="t-body"><strong>Manubrium-body</strong> fusion: ~ 60 yr</text><text x="1000" y="810" class="t-body"><strong>Vertebrae:</strong> Ring epiphyses fuse 25 yr</text><circle class="ic" cx="1520" cy="658" r="14"/><text class="t-info" x="1520" y="664" text-anchor="middle">ⓘ</text></g>

<g data-node-id="combined-xray"><rect x="60" y="860" width="1480" height="180" rx="14" fill="url(#gGrey)" filter="url(#cardShadow)"/><text x="800" y="900" class="t-nlg" text-anchor="middle">📸 X-Ray Combinations for Age Estimation</text><text x="90" y="935" class="t-body"><strong>0-5 yr:</strong> Carpal X-ray (capitate, hamate, triquetral, lunate appearance) + dentition</text><text x="90" y="960" class="t-body"><strong>5-15 yr:</strong> Wrist X-ray (carpal + distal radius epiphysis) + dentition (mixed dentition)</text><text x="90" y="985" class="t-body"><strong>15-25 yr:</strong> Wrist + elbow + shoulder X-rays (long-bone epiphyseal fusion) + 3rd molar eruption</text><text x="90" y="1010" class="t-body"><strong>&gt; 25 yr:</strong> Gustafson + skeletal changes (lipping, calcifications) + medial clavicular epiphysis</text><circle class="ic" cx="1510" cy="878" r="14"/><text class="t-info" x="1510" y="884" text-anchor="middle">ⓘ</text></g>

<rect x="60" y="1060" width="1480" height="30" rx="10" fill="url(#gOrange)"/><text x="800" y="1082" font-family="Inter,system-ui,sans-serif" font-size="13" font-weight="700" fill="white" text-anchor="middle">🎯 Scaphoid 4-7 yr · Pisiform 9-12 yr · Calcaneum/Talus at birth · Distal femur before birth = full term · Clavicle 20-22 yr last to fuse</text>
</svg>`;

const SVG_ID07 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Stature Estimation — Formulae &amp; Body Parts</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">Arm span ≈ height · Pearson · Trotter-Gleser · ↓ 1 mm/yr after 25</text>

<g data-node-id="stature-def"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">📏 STATURE — Definition &amp; General Rules</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810">Stature = body height of a person. Increases from intra-uterine life up to <strong>~ 21 yr (♂)</strong> and <strong>~ 17 yr (♀)</strong>. <strong>Max stature between 20-25 yr</strong>. After 25 yr → decreases ~ 1 mm / year. More in morning &amp; recumbent position. In dead body, stature may LENGTHEN by 2-3 cm in primary relaxation.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="stature-formulae"><rect class="body-white" x="60" y="240" width="730" height="380" rx="14"/><path d="M 74,240 H 776 A 14,14 0 0 1 790,254 V 295 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gBlue)"/><text x="80" y="280" class="t-nlg">📐 Body Part Formulae</text><text x="80" y="325" class="t-keylbl">1. Arm span (vertex to fingertip × 2 method):</text><text x="80" y="347" class="t-keyval">Distance between tips of middle fingers of overstretched arms ≈ HEIGHT</text><text x="80" y="380" class="t-keylbl">2. Vertex to symphysis pubis × 2:</text><text x="80" y="402" class="t-keyval">= stature (upper half ≈ lower half)</text><text x="80" y="435" class="t-keylbl">3. One upper limb × 2 + 34:</text><text x="80" y="457" class="t-keyval">Stature = (length tip middle finger → acromion × 2) + 34 cm</text><text x="80" y="475" class="t-keyval">(34 cm = 2 clavicles + 4 cm manubrium width)</text><text x="80" y="505" class="t-keylbl">4. Sternal notch → symphysis pubis × 3.3</text><text x="80" y="535" class="t-keylbl">5. Forearm × 3.7 (fingertip → olecranon)</text><text x="80" y="560" class="t-keylbl">6. Head length × 7 (top of head → chin)</text><text x="80" y="590" class="t-keylbl">7. Vertebral column × 35/100</text><circle class="ic" cx="770" cy="258" r="14"/><text class="t-info" x="770" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="stature-bone"><rect class="body-white" x="810" y="240" width="730" height="380" rx="14" stroke="#3D8B5B" stroke-width="3"/><path d="M 824,240 H 1526 A 14,14 0 0 1 1540,254 V 295 H 810 V 254 A 14,14 0 0 1 824,240 Z" fill="url(#gGreen)"/><text x="830" y="280" class="t-nlg">🦴 Bone-Based Regression Formulae</text><text x="830" y="325" class="t-keylbl">Karl Pearson (1899):</text><text x="830" y="347" class="t-keyval">Femur, tibia, humerus, radius regression equations</text><text x="830" y="367" class="t-keyval">e.g. ♂ Stature = 81.31 + 1.88 × femur length (cm)</text><text x="830" y="400" class="t-keylbl">Trotter &amp; Gleser (1952, 1958):</text><text x="830" y="422" class="t-keyval">Most widely used; race + sex-specific</text><text x="830" y="442" class="t-keyval">e.g. ♂ White: 64.42 + 2.32 × femur (± 3.94 cm SE)</text><text x="830" y="462" class="t-keyval">♀ Black: 28.6 + 2.34 × femur (± 3.4 cm)</text><text x="830" y="495" class="t-keylbl">Indian formulae:</text><text x="830" y="517" class="t-keyval">• Pan (1924) · Singh &amp; Sohal · Pheasant (1986) · Nat (1931)</text><text x="830" y="537" class="t-keyval">• Used by Indian forensic labs for skeletal cases</text><text x="830" y="570" class="t-keylbl">★ Hand length / breadth regression (Bhatnagar 1984):</text><text x="830" y="590" class="t-keyval">Stature = 127.97 + 2.06 × hand length</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="stature-foot"><rect x="60" y="640" width="900" height="220" rx="14" fill="url(#gOrange)" filter="url(#cardShadow)"/><text x="510" y="680" class="t-nlg" text-anchor="middle">👣 Footprint &amp; Foot Length</text><text x="90" y="715" class="t-body"><strong>Stature ≈ 6 × foot length</strong> (rough estimate)</text><text x="90" y="745" class="t-body"><strong>Footprint analysis:</strong></text><text x="90" y="770" class="t-body">• Pattern, length, width, ridge characteristics</text><text x="90" y="795" class="t-body">• Shoe prints — make + size + wear pattern can identify gait/manner of walking</text><text x="90" y="820" class="t-body" font-style="italic">★ "Dermatoglyphics of foot" — like fingerprints, individual</text><text x="90" y="845" class="t-body" font-style="italic">★ Useful at crime scene · in temple footprints (religious significance)</text><circle class="ic" cx="940" cy="658" r="14"/><text class="t-info" x="940" y="664" text-anchor="middle">ⓘ</text></g>

<g data-node-id="stature-skel"><rect x="980" y="640" width="560" height="220" rx="14" fill="url(#gPurple)" filter="url(#cardShadow)"/><text x="1260" y="680" class="t-nlg" text-anchor="middle">💀 In Skeletal Remains</text><text x="1000" y="715" class="t-body">★ Femur is the MOST RELIABLE single bone</text><text x="1000" y="740" class="t-body">★ Combined long bones (femur + tibia + humerus +</text><text x="1000" y="760" class="t-body">radius) give highest accuracy</text><text x="1000" y="790" class="t-body"><strong>Vertebral column:</strong></text><text x="1000" y="810" class="t-body">Stature = vertebral column × 35/100</text><text x="1000" y="835" class="t-body" font-style="italic">★ If only fragments — use any long bone available</text><circle class="ic" cx="1520" cy="658" r="14"/><text class="t-info" x="1520" y="664" text-anchor="middle">ⓘ</text></g>

<g data-node-id="stature-variations"><rect x="60" y="880" width="1480" height="160" rx="14" fill="url(#gRed)" filter="url(#cardShadow)"/><text x="800" y="920" class="t-nlg" text-anchor="middle">⚖️ Diurnal &amp; Postmortem Variations</text><text x="90" y="955" class="t-body"><strong>HIGHER stature when:</strong> 20-25 yr (max) · morning hours · recumbent position · primary relaxation (dead body)</text><text x="90" y="980" class="t-body"><strong>LOWER stature when:</strong> evening (after a day of weight-bearing → disc compression) · standing · during rigor mortis</text><text x="90" y="1005" class="t-body"><strong>After 25 yr:</strong> stature decreases ~ 1 mm / year (cumulative loss of intervertebral disc height + kyphosis)</text><circle class="ic" cx="1510" cy="898" r="14"/><text class="t-info" x="1510" y="904" text-anchor="middle">ⓘ</text></g>
</svg>`;

const SVG_ID08 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Race Determination — Caucasoid · Mongoloid · Negroid</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">Complexion · hair · skull · palate · hand-foot · cephalic index</text>

<g data-node-id="race-def"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">🌍 RACE — Definition</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810">A <strong>biological grouping within the human species</strong> distinguished or classified according to genetically transmitted differences. Race is a <strong>POPULATION</strong> concept — populations differing in the frequency of some genes. World population → 3 racial types: <strong>Caucasoid · Mongoloid · Negroid</strong>.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="caucasoid"><rect class="body-white" x="60" y="240" width="490" height="400" rx="14" stroke="#15294F" stroke-width="3"/><path d="M 74,240 H 536 A 14,14 0 0 1 550,254 V 295 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gBlue)"/><text x="80" y="280" class="t-nlg">⚪ CAUCASOID</text><text x="80" y="325" class="t-keylbl">Complexion:</text><text x="200" y="325" class="t-keyval">Fair</text><text x="80" y="350" class="t-keylbl">Iris colour:</text><text x="180" y="350" class="t-keyval">Gray or blue</text><text x="80" y="375" class="t-keylbl">Hair:</text><text x="140" y="375" class="t-keyval">Straight or wavy, blonde/brown/fair</text><text x="80" y="395" class="t-keyval">Diameter 70-100 µm · oval cross-section</text><text x="80" y="425" class="t-keylbl">Forehead:</text><text x="180" y="425" class="t-keyval">RAISED</text><text x="80" y="450" class="t-keylbl">Nose:</text><text x="140" y="450" class="t-keyval">Sharp · Nasal aperture narrow + elongated</text><text x="80" y="475" class="t-keylbl">Face:</text><text x="140" y="475" class="t-keyval">Small</text><text x="80" y="500" class="t-keylbl">Hard palate:</text><text x="200" y="500" class="t-keyval">TRIANGULAR</text><text x="80" y="525" class="t-keylbl">Upper / lower limb:</text><text x="270" y="525" class="t-keyval">Normal proportions</text><text x="80" y="560" class="t-keylbl">Skull shape:</text><text x="200" y="560" class="t-keyval">Dolichocephalic (long-headed)</text><text x="80" y="590" class="t-keyval">Cephalic index &lt; 75</text><circle class="ic" cx="540" cy="258" r="14"/><text class="t-info" x="540" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="mongoloid"><rect class="body-white" x="570" y="240" width="490" height="400" rx="14" stroke="#C58A3D" stroke-width="3"/><path d="M 584,240 H 1046 A 14,14 0 0 1 1060,254 V 295 H 570 V 254 A 14,14 0 0 1 584,240 Z" fill="url(#gOrange)"/><text x="590" y="280" class="t-nlg">🟡 MONGOLOID</text><text x="590" y="325" class="t-keylbl">Complexion:</text><text x="710" y="325" class="t-keyval">Yellowish</text><text x="590" y="350" class="t-keylbl">Iris colour:</text><text x="690" y="350" class="t-keyval">Black</text><text x="590" y="375" class="t-keylbl">Hair:</text><text x="650" y="375" class="t-keyval">Coarse, straight or wavy, black/brown</text><text x="590" y="395" class="t-keyval">Diameter 90-120 µm · round cross-section · thick cuticle</text><text x="590" y="425" class="t-keylbl">Forehead:</text><text x="690" y="425" class="t-keyval">Inclined backward</text><text x="590" y="450" class="t-keylbl">Nose:</text><text x="650" y="450" class="t-keyval">Flattened · nasal aperture rounded</text><text x="590" y="475" class="t-keylbl">Face:</text><text x="650" y="475" class="t-keyval">Large + flattened (high cheekbones)</text><text x="590" y="500" class="t-keylbl">Hard palate:</text><text x="710" y="500" class="t-keyval">LARGE &amp; FLATTENED</text><text x="590" y="525" class="t-keylbl">Upper / lower limb:</text><text x="780" y="525" class="t-keyval">Small</text><text x="590" y="560" class="t-keylbl">Skull shape:</text><text x="710" y="560" class="t-keyval">Brachycephalic (round)</text><text x="590" y="590" class="t-keyval">Cephalic index &gt; 80 · "epicanthic fold" of eyes</text><circle class="ic" cx="1050" cy="258" r="14"/><text class="t-info" x="1050" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="negroid"><rect class="body-white" x="1080" y="240" width="460" height="400" rx="14" stroke="#A14B47" stroke-width="3"/><path d="M 1094,240 H 1526 A 14,14 0 0 1 1540,254 V 295 H 1080 V 254 A 14,14 0 0 1 1094,240 Z" fill="url(#gRed)"/><text x="1090" y="280" class="t-nlg">⚫ NEGROID</text><text x="1090" y="325" class="t-keylbl">Complexion:</text><text x="1210" y="325" class="t-keyval">Black</text><text x="1090" y="350" class="t-keylbl">Iris:</text><text x="1140" y="350" class="t-keyval">Black</text><text x="1090" y="375" class="t-keylbl">Hair:</text><text x="1150" y="375" class="t-keyval">Thick, woolly, curly, spiraled</text><text x="1090" y="395" class="t-keyval">Diameter 60-90 µm · flattened cross-section</text><text x="1090" y="425" class="t-keylbl">Forehead:</text><text x="1200" y="425" class="t-keyval">Small + compressed</text><text x="1090" y="450" class="t-keylbl">Nose:</text><text x="1150" y="450" class="t-keyval">Blunt · nasal aperture BROAD</text><text x="1090" y="475" class="t-keylbl">Face:</text><text x="1140" y="475" class="t-keyval">Jaw projects (prognathism),</text><text x="1090" y="495" class="t-keyval">teeth set obliquely, malar prominence</text><text x="1090" y="520" class="t-keylbl">Hard palate:</text><text x="1210" y="520" class="t-keyval">RECTANGULAR</text><text x="1090" y="545" class="t-keylbl">Upper limb:</text><text x="1210" y="545" class="t-keyval">Long; forearm long vs arm</text><text x="1090" y="565" class="t-keylbl">Lower limb:</text><text x="1210" y="565" class="t-keyval">Leg long vs thigh · heel projects backward</text><text x="1090" y="595" class="t-keyval">Wide flat feet · cephalic index &lt; 75 (dolicho.)</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="cephalic-index"><rect x="60" y="660" width="900" height="200" rx="14" fill="url(#gPurple)" filter="url(#cardShadow)"/><text x="510" y="700" class="t-nlg" text-anchor="middle">📐 CEPHALIC INDEX</text><text x="90" y="735" class="t-body"><strong>Formula:</strong> (max breadth / max length of skull) × 100</text><text x="90" y="760" class="t-body"><strong>Dolichocephalic (long-headed):</strong> &lt; 75 — Caucasoid, Negroid, Pure Aryans</text><text x="90" y="785" class="t-body"><strong>Mesocephalic (medium):</strong> 75-80 — Europeans, Indian average</text><text x="90" y="810" class="t-body"><strong>Brachycephalic (round-headed):</strong> &gt; 80 — Mongoloid, some Europeans</text><text x="90" y="835" class="t-body" font-style="italic">★ Cephalic index also used in identifying race + ethnic ancestry</text><circle class="ic" cx="940" cy="678" r="14"/><text class="t-info" x="940" y="684" text-anchor="middle">ⓘ</text></g>

<g data-node-id="other-indices"><rect x="980" y="660" width="560" height="200" rx="14" fill="url(#gGrey)" filter="url(#cardShadow)"/><text x="1260" y="700" class="t-nlg" text-anchor="middle">📊 Other Anthropometric Indices</text><text x="1000" y="735" class="t-body"><strong>Nasal index</strong> = (nasal width / nasal height) × 100</text><text x="1000" y="755" class="t-body">Leptorrhine &lt; 70 (Caucasoid) · Platyrrhine &gt; 85 (Negroid)</text><text x="1000" y="780" class="t-body"><strong>Orbital index</strong> = (orbital height / breadth) × 100</text><text x="1000" y="805" class="t-body"><strong>Facial index</strong> = (face length / breadth) × 100</text><text x="1000" y="830" class="t-body">Leptoprosopic (long) vs Euryprosopic (broad)</text><circle class="ic" cx="1520" cy="678" r="14"/><text class="t-info" x="1520" y="684" text-anchor="middle">ⓘ</text></g>

<rect x="60" y="880" width="1480" height="60" rx="10" fill="url(#gOrange)"/><text x="800" y="918" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="700" fill="white" text-anchor="middle">🎯 3 races: Caucasoid (triangular palate, sharp nose) · Mongoloid (large flattened palate, round skull) · Negroid (rectangular palate, broad nose)</text>

<rect x="60" y="960" width="1480" height="40" rx="10" fill="url(#gBlue)"/><text x="800" y="988" font-family="Inter,system-ui,sans-serif" font-size="13" font-weight="700" fill="white" text-anchor="middle">📚 Hair: Caucasoid oval · Mongoloid round · Negroid flattened · Cephalic index distinguishes long vs round skulls</text>

<rect x="60" y="1020" width="1480" height="40" rx="10" fill="url(#gGrey)"/><text x="800" y="1048" font-family="Inter,system-ui,sans-serif" font-size="13" font-weight="700" fill="white" text-anchor="middle">⚠️ Race classification is controversial — modern forensics uses geographic ancestry + DNA SNPs rather than rigid 3-race categories</text>
</svg>`;

const SVG_ID09 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Fingerprints (Dactyloscopy) — Galton System</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">4 types · loop 65% · whorl 25% · arch 7% · composite 2-3% · 16-20 points match</text>

<g data-node-id="fp-def"><rect class="nbcr" x="60" y="110" width="1480" height="100" rx="14"/><text x="90" y="148" font-family="Inter,system-ui,sans-serif" font-size="16" font-weight="800" fill="#8B6914">🖐️ FINGERPRINTS — Definition &amp; Synonyms</text><text x="90" y="180" font-family="Inter,system-ui,sans-serif" font-size="14" font-weight="500" fill="#5C4810"><strong>Synonyms:</strong> Dactylography · Dermatoglyphics · <strong>Galton system</strong>. Fingerprints are impressions of patterns formed by the <strong>papillary (epidermal) ridges</strong> of the fingertips. The basis: individual peculiarities are <strong>ABSOLUTELY CONSTANT</strong> and persist throughout life from infancy to old age, and no two hands resemble each other.</text><circle class="ic" cx="1500" cy="130" r="14"/><text class="t-info" x="1500" y="136" text-anchor="middle">ⓘ</text></g>

<g data-node-id="fp-features"><rect class="body-white" x="60" y="240" width="490" height="380" rx="14" stroke="#15294F" stroke-width="3"/><path d="M 74,240 H 536 A 14,14 0 0 1 550,254 V 295 H 60 V 254 A 14,14 0 0 1 74,240 Z" fill="url(#gBlue)"/><text x="80" y="280" class="t-nlg">✨ Key Features</text><text x="80" y="325" class="t-keyval">★ <strong>Identification by this system is ABSOLUTE</strong></text><text x="80" y="365" class="t-keyval">★ Highly individualistic — even in <strong>MONOZYGOTIC TWINS</strong></text><text x="80" y="385" class="t-keyval"><strong>★ NEET-PG 2019 Q5</strong> verbatim</text><text x="80" y="425" class="t-keyval">★ Form during <strong>INTRA-UTERINE LIFE</strong>:</text><text x="80" y="447" class="t-keyval">- Primary epidermal ridges appear at <strong>2-3 month IUL</strong></text><text x="80" y="467" class="t-keyval">- Secondary ridges develop by 5th month</text><text x="80" y="487" class="t-keyval">- Fully formed and permanent by 24 weeks IUL</text><text x="80" y="520" class="t-keyval">★ Chances of 2 identical prints: <strong>1 in 64 billion</strong></text><text x="80" y="555" class="t-keyval">★ Follows <strong>Quetelet\'s rule</strong> — "all nature-made</text><text x="80" y="575" class="t-keyval">things have unlimited and infinite variations of form"</text><circle class="ic" cx="540" cy="258" r="14"/><text class="t-info" x="540" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="fp-types"><rect class="body-white" x="570" y="240" width="490" height="380" rx="14" stroke="#3D8B5B" stroke-width="3"/><path d="M 584,240 H 1046 A 14,14 0 0 1 1060,254 V 295 H 570 V 254 A 14,14 0 0 1 584,240 Z" fill="url(#gGreen)"/><text x="590" y="280" class="t-nlg">📋 4 Types — Galton Classification</text><text x="590" y="325" class="t-keylbl">1. LOOP — 65% ★ commonest</text><text x="590" y="345" class="t-keyval">• Ulnar loop (opens toward little finger)</text><text x="590" y="365" class="t-keyval">• Radial loop (opens toward thumb)</text><text x="590" y="395" class="t-keylbl">2. WHORL — 25%</text><text x="590" y="415" class="t-keyval">• Concentric · spiral CW · spiral CCW</text><text x="590" y="435" class="t-keyval">• Double spiral · almond shape</text><text x="590" y="465" class="t-keylbl">3. ARCH — 7%</text><text x="590" y="485" class="t-keyval">• Plain arch · tented arch · exceptional</text><text x="590" y="515" class="t-keylbl">4. COMPOSITE — 2-3% ★ rarest</text><text x="590" y="535" class="t-keyval">• Central pocket loop · twined loop · accidental</text><text x="590" y="565" class="t-keyval" font-style="italic">★ Mnemonic: "Loops Wear Aprons Carelessly"</text><text x="590" y="585" class="t-keyval" font-style="italic">(Loop &gt; Whorl &gt; Arch &gt; Composite)</text><circle class="ic" cx="1050" cy="258" r="14"/><text class="t-info" x="1050" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="fp-recording"><rect class="body-white" x="1080" y="240" width="460" height="380" rx="14"/><path d="M 1094,240 H 1526 A 14,14 0 0 1 1540,254 V 295 H 1080 V 254 A 14,14 0 0 1 1094,240 Z" fill="url(#gOrange)"/><text x="1090" y="280" class="t-nlg">🖨️ Recording Methods</text><text x="1090" y="325" class="t-keylbl">PLAIN method:</text><text x="1090" y="347" class="t-keyval">Inked finger pressed onto unglazed paper</text><text x="1090" y="367" class="t-keyval">+ Quick + easy</text><text x="1090" y="385" class="t-keyval">− Smaller area for comparison</text><text x="1090" y="420" class="t-keylbl">ROLLED method:</text><text x="1090" y="442" class="t-keyval">Finger rolled outward → inward on paper</text><text x="1090" y="462" class="t-keyval">+ Larger surface area</text><text x="1090" y="482" class="t-keyval">− More difficult; may blur</text><text x="1090" y="515" class="t-keylbl">Comparison criteria:</text><text x="1090" y="537" class="t-keyval">• <strong>16-20 matching points</strong> = positive ID ★</text><text x="1090" y="557" class="t-keyval">• Ridge ending · pattern · delta · core ·</text><text x="1090" y="577" class="t-keyval">island · fork · bifurcation · ridge count</text><circle class="ic" cx="1530" cy="258" r="14"/><text class="t-info" x="1530" y="264" text-anchor="middle">ⓘ</text></g>

<g data-node-id="fp-scene"><rect x="60" y="640" width="900" height="220" rx="14" fill="url(#gPurple)" filter="url(#cardShadow)"/><text x="510" y="680" class="t-nlg" text-anchor="middle">🔎 Fingerprints at Crime Scene — 3 Types</text><text x="90" y="715" class="t-body"><strong>1. VISIBLE prints</strong> — fingers smeared with blood / paint / oil / dust / secretion → directly visible</text><text x="90" y="745" class="t-body"><strong>2. PLASTIC prints</strong> — on soft surfaces (soap, wax, clay, cheese) → 3-D impression</text><text x="90" y="775" class="t-body"><strong>3. LATENT prints</strong> ★ — invisible or barely visible · from sweat + sebum deposits · need REAGENTS to develop</text><text x="90" y="800" class="t-body">• Powder methods (aluminium, black, magnetic)</text><text x="90" y="820" class="t-body">• Chemical (ninhydrin → purple amino acid stain · cyanoacrylate fuming · silver nitrate · iodine)</text><text x="90" y="840" class="t-body">• "Chance fingerprints" — accidental latent prints, common at crime scene</text><circle class="ic" cx="940" cy="658" r="14"/><text class="t-info" x="940" y="664" text-anchor="middle">ⓘ</text></g>

<g data-node-id="fp-uses"><rect x="980" y="640" width="560" height="220" rx="14" fill="url(#gRed)" filter="url(#cardShadow)"/><text x="1260" y="680" class="t-nlg" text-anchor="middle">⚖️ Medicolegal Uses</text><text x="1000" y="715" class="t-body">• Identification of unknown bodies</text><text x="1000" y="740" class="t-body">• Habitual criminals (NCRB AFIS database)</text><text x="1000" y="765" class="t-body">• Aadhaar (UIDAI) — biometric ID</text><text x="1000" y="790" class="t-body">• Disputed identity / paternity (with DNA)</text><text x="1000" y="815" class="t-body">• Documents — signatures, forgeries</text><text x="1000" y="840" class="t-body">• Crime scene reconstruction</text><circle class="ic" cx="1520" cy="658" r="14"/><text class="t-info" x="1520" y="664" text-anchor="middle">ⓘ</text></g>

<g data-node-id="fp-history"><rect x="60" y="880" width="1480" height="160" rx="14" fill="url(#gGrey)" filter="url(#cardShadow)"/><text x="800" y="920" class="t-nlg" text-anchor="middle">📜 History of Fingerprint Identification</text><text x="90" y="955" class="t-body"><strong>Henry Faulds (1880)</strong> — first proposed fingerprints for identification</text><text x="90" y="980" class="t-body"><strong>Sir Francis Galton (1892)</strong> — "Finger Prints" book; classified into types ★</text><text x="90" y="1005" class="t-body"><strong>Sir Edward Henry (1897)</strong> — Henry classification system, adopted at Bengal Police</text><text x="90" y="1030" class="t-body"><strong>Juan Vucetich (1892)</strong> — Argentina · first conviction based on fingerprints</text><circle class="ic" cx="1510" cy="898" r="14"/><text class="t-info" x="1510" y="904" text-anchor="middle">ⓘ</text></g>
</svg>`;

const SVG_ID10 = `<svg viewBox="0 0 1600 1100" xmlns="http://www.w3.org/2000/svg" class="diagram-svg">
${STYLE}
<text class="t-title" x="800" y="50" text-anchor="middle">Tattoos · Scars · Deformities · Anthropometry · Posthumous Child</text>
<text class="t-sub" x="800" y="80" text-anchor="middle">Secondary identifiers + Bertillon system + 7-yr presumption of death</text>

<g data-node-id="tattoo-def"><rect class="body-white" x="60" y="110" width="730" height="300" rx="14" stroke="#7B5FA8" stroke-width="3"/><path d="M 74,110 H 776 A 14,14 0 0 1 790,124 V 165 H 60 V 124 A 14,14 0 0 1 74,110 Z" fill="url(#gPurple)"/><text x="80" y="150" class="t-nlg">🎨 TATTOO MARKS</text><text x="80" y="195" class="t-keylbl">Definition:</text><text x="80" y="215" class="t-keyval">Designs effected by multiple small puncture wounds through</text><text x="80" y="235" class="t-keyval">skin with needles dipped in colouring material (dye).</text><text x="80" y="265" class="t-keylbl">Dyes used:</text><text x="80" y="285" class="t-keyval">• Carbon (India ink) / China ink / soot — BLACK</text><text x="80" y="305" class="t-keyval">• Cinnabar / vermilion — RED</text><text x="80" y="325" class="t-keyval">• Ochre — BROWN · Chromic oxide — GREEN</text><text x="80" y="345" class="t-keyval">• Prussian blue (ferric ferrocyanide), indigo, cobalt, ultramarine — BLUE</text><text x="80" y="375" class="t-keylbl">Persistence:</text><text x="80" y="395" class="t-keyval">Usually distinct up to ~ 10 years</text><circle class="ic" cx="770" cy="128" r="14"/><text class="t-info" x="770" y="134" text-anchor="middle">ⓘ</text></g>

<g data-node-id="tattoo-reveal"><rect class="body-white" x="810" y="110" width="730" height="300" rx="14" stroke="#A14B47" stroke-width="3"/><path d="M 824,110 H 1526 A 14,14 0 0 1 1540,124 V 165 H 810 V 124 A 14,14 0 0 1 824,110 Z" fill="url(#gRed)"/><text x="830" y="150" class="t-nlg">🔍 Revealing FADED Tattoos ★</text><text x="830" y="195" class="t-keylbl">Methods:</text><text x="830" y="215" class="t-keyval">1. <strong>UV light</strong> (filtered)</text><text x="830" y="235" class="t-keyval">2. <strong>Infrared photography</strong></text><text x="830" y="255" class="t-keyval">3. Rubbing area + magnifying glass</text><text x="830" y="275" class="t-keyval">4. If obscured by decomposition → <strong>3% H₂O₂</strong></text><text x="830" y="295" class="t-keyval">5. Treatment with <strong>0.5% caustic potash (KOH)</strong></text><text x="830" y="320" class="t-keyval">6. <strong>★ EXAMINE REGIONAL LYMPH NODES</strong></text><text x="830" y="340" class="t-keyval">Lymph nodes near tattoo show DEPOSIT OF PIGMENT</text><text x="830" y="365" class="t-keyval"><strong>★ NEET-PG 2020 Q3</strong>: Invisible tattoo →</text><text x="830" y="385" class="t-keyval">examine the LYMPH NODE (verbatim)</text><circle class="ic" cx="1530" cy="128" r="14"/><text class="t-info" x="1530" y="134" text-anchor="middle">ⓘ</text></g>

<g data-node-id="scars"><rect class="body-white" x="60" y="430" width="490" height="320" rx="14"/><path d="M 74,430 H 536 A 14,14 0 0 1 550,444 V 485 H 60 V 444 A 14,14 0 0 1 74,430 Z" fill="url(#gOrange)"/><text x="80" y="470" class="t-nlg">🩹 SCARS</text><text x="80" y="515" class="t-keylbl">Definition:</text><text x="80" y="535" class="t-keyval">Fibrous tissue from healing of wound; covered by</text><text x="80" y="555" class="t-keyval">epithelium DEVOID of hair follicles, sweat glands, pigment</text><text x="80" y="585" class="t-keylbl">Features:</text><text x="80" y="605" class="t-keyval">• Permanent · cannot be erased completely</text><text x="80" y="625" class="t-keyval">• Requires injury to DERMIS (epidermal injury heals without scar)</text><text x="80" y="650" class="t-keyval">• Assumes shape of original wound:</text><text x="100" y="670" class="t-keyval">- Incised → linear · Lacerated → broad irregular</text><text x="100" y="690" class="t-keyval">- Stab → oval/elliptical/triangular</text><text x="100" y="710" class="t-keyval">- Scald → spotted, running down · Vaccination → round</text><text x="80" y="735" class="t-keyval" font-style="italic">★ Striae gravidarum = past pregnancy marker</text><circle class="ic" cx="540" cy="448" r="14"/><text class="t-info" x="540" y="454" text-anchor="middle">ⓘ</text></g>

<g data-node-id="deformities"><rect class="body-white" x="570" y="430" width="490" height="320" rx="14"/><path d="M 584,430 H 1046 A 14,14 0 0 1 1060,444 V 485 H 570 V 444 A 14,14 0 0 1 584,430 Z" fill="url(#gGreen)"/><text x="590" y="470" class="t-nlg">🦴 DEFORMITIES</text><text x="590" y="515" class="t-keylbl">A. Congenital:</text><text x="590" y="535" class="t-keyval">• Cleft palate · hare lip</text><text x="590" y="555" class="t-keyval">• Polydactyly · syndactyly · webbed fingers</text><text x="590" y="575" class="t-keyval">• Claw hand · birthmark (naevi) · moles</text><text x="590" y="595" class="t-keyval">• Kyphosis (hump back) · port wine stain</text><text x="590" y="615" class="t-keyval">• Mongolian spots · Hutchinson teeth</text><text x="590" y="645" class="t-keylbl">B. Acquired:</text><text x="590" y="665" class="t-keyval">• Poliomyelitis · contracture · paralysis</text><text x="590" y="685" class="t-keyval">• Mal-united / non-united fractures</text><text x="590" y="705" class="t-keyval">• Old amputations · surgical scars</text><text x="590" y="725" class="t-keyval">• Occupation marks (callus, dye stains)</text><circle class="ic" cx="1050" cy="448" r="14"/><text class="t-info" x="1050" y="454" text-anchor="middle">ⓘ</text></g>

<g data-node-id="anthropometry"><rect class="body-white" x="1080" y="430" width="460" height="320" rx="14"/><path d="M 1094,430 H 1526 A 14,14 0 0 1 1540,444 V 485 H 1080 V 444 A 14,14 0 0 1 1094,430 Z" fill="url(#gBlue)"/><text x="1090" y="470" class="t-nlg">📏 ANTHROPOMETRY (Bertillon)</text><text x="1090" y="515" class="t-keylbl">Bertillon system (1879, France):</text><text x="1090" y="535" class="t-keyval">Based on principle:</text><text x="1090" y="555" class="t-keyval">1. After 21 yr, body part measurements DO</text><text x="1090" y="575" class="t-keyval">NOT alter</text><text x="1090" y="595" class="t-keyval">2. Ratio of body parts varies between individuals</text><text x="1090" y="625" class="t-keylbl">Records:</text><text x="1090" y="645" class="t-keyval">• Descriptive (iris, hair, complexion)</text><text x="1090" y="665" class="t-keyval">• Body marks (moles, scars, tattoos)</text><text x="1090" y="685" class="t-keyval">• Standing/sitting height, head L+W, ear, span, foot</text><text x="1090" y="715" class="t-keyval" font-style="italic">★ Replaced by fingerprint system due to:</text><text x="1090" y="735" class="t-keyval" font-style="italic">subjective error, adult-only, manpower needed</text><circle class="ic" cx="1530" cy="448" r="14"/><text class="t-info" x="1530" y="454" text-anchor="middle">ⓘ</text></g>

<g data-node-id="posthumous"><rect x="60" y="770" width="900" height="180" rx="14" fill="url(#gRed)" filter="url(#cardShadow)"/><text x="510" y="810" class="t-nlg" text-anchor="middle">👶 POSTHUMOUS CHILD ★</text><text x="90" y="848" class="t-body"><strong>Definition:</strong> A child <strong>BORN AFTER THE DEATH OF THE BIOLOGICAL FATHER</strong>.</text><text x="90" y="875" class="t-body">• Legal recognition: in inheritance and succession matters (Hindu Succession Act, Indian Succession Act)</text><text x="90" y="900" class="t-body">• Must be conceived BEFORE father\'s death · DNA may be required to prove paternity</text><text x="90" y="925" class="t-body" font-style="italic">★ NEET-PG 2018 Q2 + 2024 Q1 (verbatim): "Child delivered after death of biological father"</text><circle class="ic" cx="940" cy="788" r="14"/><text class="t-info" x="940" y="794" text-anchor="middle">ⓘ</text></g>

<g data-node-id="presumption-death"><rect x="980" y="770" width="560" height="180" rx="14" fill="url(#gGrey)" filter="url(#cardShadow)"/><text x="1260" y="810" class="t-nlg" text-anchor="middle">⏳ 7-YEAR PRESUMPTION of Death</text><text x="1000" y="848" class="t-body"><strong>BSA § 110</strong> (≡ IEA § 108):</text><text x="1000" y="873" class="t-body">If person not heard of for <strong>7 YEARS</strong> by those</text><text x="1000" y="898" class="t-body">who would have heard if alive → court PRESUMES</text><text x="1000" y="923" class="t-body">them DEAD.</text><text x="1000" y="945" class="t-body" font-style="italic">★ NEET-PG 2016 Q10 verbatim</text><circle class="ic" cx="1520" cy="788" r="14"/><text class="t-info" x="1520" y="794" text-anchor="middle">ⓘ</text></g>

<g data-node-id="other-secondary"><rect x="60" y="970" width="1480" height="100" rx="14" fill="url(#gOrange)" filter="url(#cardShadow)"/><text x="800" y="1010" class="t-nlg" text-anchor="middle">📎 Other Secondary Identifiers — Quick Reference</text><text x="90" y="1045" class="t-body"><strong>Cheiloscopy</strong> (lip prints) · <strong>Palatal rugoscopy</strong> · <strong>Frontal sinus radiographs</strong> · <strong>Ear morphology</strong> (helix/lobule pattern) · <strong>Footprints + foot-length-to-height ratio</strong> · <strong>Handwriting</strong> · <strong>Voice analysis</strong></text><circle class="ic" cx="1510" cy="988" r="14"/><text class="t-info" x="1510" y="994" text-anchor="middle">ⓘ</text></g>
</svg>`;


const NODES = {
  'id-def': { label: 'Identification — Definition', info: '<p><strong>Identification</strong> = recognition of an individual based on physical, biological, dental, fingerprint, or DNA characteristics.</p><p><strong>UN Declaration:</strong> "Everyone has the right to recognition everywhere as a person before the law."</p><p>Required in CIVIL (inheritance, insurance, marriage) and CRIMINAL (assault, murder, criminal abortion, age of responsibility) contexts.</p>', tags: ['UN right'] },
  'id-living': { label: 'Identification — In Living Persons', info: '<p><strong>A. Civil cases:</strong></p><ul><li>Impersonation — inheritance, pension, life insurance, voting, passport</li><li>Disputed identity in divorce / nullity of marriage</li><li>Disputed sex · missing person · lost memory (amnesia)</li></ul><p><strong>B. Criminal cases:</strong></p><ul><li>Accused in assault, murder, dacoity, sexual offences</li><li>Absconding soldiers</li><li>Interchange of newborns in hospital</li><li>Criminal abortion</li><li>Fixing age of criminal responsibility &amp; majority</li><li>Impersonation in criminal proceedings</li></ul>', tags: ['Civil + Criminal'] },
  'id-dead': { label: 'Identification — In Dead Persons', info: '<p>Required for individuals who died in:</p><ul><li>Mass disasters · air-crash accidents · fire victims</li><li>Exhumation cases</li><li>Explosion / bomb blast injuries</li><li>Mutilated &amp; decomposed bodies</li><li>Skeletal remains</li></ul><p>★ <strong>In India, the POLICE establish identity</strong>; the doctor supplies <strong>facts/data</strong> to assist.</p><p>★ During every medicolegal examination, the doctor must record <strong>AT LEAST 2 identification marks</strong> in the MLC certificate.</p>', tags: ['Police establishes', 'Doctor supplies data'] },
  'id-corpus': { label: 'Corpus Delicti', info: '<p><strong>Corpus delicti</strong> (Latin: "body of crime") = the <strong>body / essence of the offence</strong> — what must be established to prove a crime occurred.</p><p><strong>In homicide it requires:</strong></p><ol><li>Identification of the dead body (who the victim is)</li><li>Conclusive evidence that the death was caused by a CRIMINAL ACT (not natural, accidental, or suicidal)</li></ol><p>★ Corpus delicti is the foundation for any homicide trial.</p><p>★ Convictions have occurred even in absence of corpus delicti (e.g., destroyed body), but proving corpus delicti is the prosecution\'s strongest evidence.</p>', tags: ['Body of crime'] },
  'id-data16': { label: '16 Data Points for Identification', info: '<ol><li>Religion</li><li>Race</li><li>Sex</li><li>Age</li><li>Stature</li><li>Dactylography (fingerprints)</li><li>Footprints</li><li>Cheiloscopy (lip prints)</li><li>Tattoo marks</li><li>Scars</li><li>Deformities</li><li>Anthropometry</li><li>Teeth (dentition)</li><li>DNA typing</li><li>Blood group + HLA typing</li><li>Miscellaneous — complexion, hair, clothes, personal effects, handwriting, signature, voice, occupation marks, gait, habits, ear morphology, palate prints, frontal sinuses, X-ray, ECG (Sreenivas), namaste technique (Subrahmanyam)</li></ol>', tags: ['16-point checklist'] },
  'id-locard': { label: 'Locard\'s Exchange Principle', info: '<p><strong>Edmond Locard</strong> (French criminologist, 1877-1966):</p><p>"Every contact leaves a trace."</p><p><strong>Principle:</strong> When two objects come into contact, there is always a TRANSFER of material between them.</p><p><strong>Forensic implications:</strong></p><ul><li>Perpetrator carries away material from the scene/victim (hair, fibre, fluid)</li><li>Perpetrator leaves their own material at scene/on victim (DNA, fibre, GSR)</li><li>Foundation of TRACE EVIDENCE forensics</li></ul><p>★ <strong>NEET-PG 2018 Q6</strong> verbatim — Locard = theory of exchange.</p>', tags: ['PYQ 2018 Q6'] },

  'pri-sec-key': { label: 'Primary vs Secondary Identifiers', info: '<p>Per <strong>Interpol Disaster Victim Identification (DVI)</strong> protocol:</p><ul><li><strong>Primary identifiers</strong> — individually sufficient for positive identification</li><li><strong>Secondary identifiers</strong> — only supportive; not stand-alone</li></ul><p>In disaster scenarios, the use of multiple secondary identifiers may collectively suffice when no primary is available, but visual recognition alone is unreliable and often misleading in mass casualty.</p>', tags: ['Interpol DVI'] },
  'primary-id': { label: 'Primary Identifiers — 3 only', info: '<ol><li><strong>FINGERPRINTS (Dactyloscopy)</strong><ul><li>Form in 2-5 month IUL; permanent throughout life</li><li>Individual even in MONOZYGOTIC TWINS</li><li>16-20 matching points = positive ID</li></ul></li><li><strong>DENTAL RECORDS</strong><ul><li>Compared with antemortem dental chart, X-ray, restorations</li><li>Survives fire, putrefaction, skeletalisation</li></ul></li><li><strong>DNA PROFILE</strong><ul><li>STR analysis · 13 CODIS loci</li><li>Gold standard for decomposed / fragmented bodies</li><li>Reference: toothbrush, hairbrush, family DNA</li></ul></li></ol><p>★ <strong>Any ONE primary identifier alone = positive identification</strong>.</p>', tags: ['FP · Dental · DNA'] },
  'secondary-id': { label: 'Secondary Identifiers — Supportive', info: '<ul><li><strong>Visual recognition</strong> by relatives (unreliable in disasters / decomposition)</li><li><strong>Personal effects</strong> — clothes, jewellery, watch, ID card, mobile phone</li><li><strong>Body modifications</strong> — tattoos, scars, piercings, birthmarks, moles</li><li><strong>Acquired deformities</strong> — old fractures, amputations, mal-union</li><li><strong>Congenital deformities</strong> — cleft palate, polydactyly, claw hand, kyphosis</li><li><strong>Occupation marks</strong> — callosities, dye stains, tailor\'s notch</li><li><strong>Anthropometric data</strong> (Bertillon — historical)</li><li><strong>Photographs · handwriting · voice samples</strong></li><li><strong>Surgical implants</strong> — pacemaker, hip prosthesis (with serial number)</li><li><strong>Medical conditions</strong> — DM, CHD, prior surgeries</li></ul><p>★ Multiple secondaries together may suffice if no primary is available.</p>', tags: ['Multiple required'] },
  'dvi-protocol': { label: 'Interpol DVI Protocol', info: '<p><strong>Disaster Victim Identification (DVI)</strong> — Interpol standard for mass casualty:</p><ul><li><strong>Pink form</strong> — postmortem (PM) data collected from body at scene/morgue</li><li><strong>Yellow form</strong> — antemortem (AM) data collected from family/dentist/doctor</li><li><strong>Reconciliation phase</strong> — PM and AM data are matched</li><li>Identification confirmed when at least 1 primary identifier OR strong combination of secondaries matches</li></ul><p>★ Used in India after 2004 tsunami, 26/11 Mumbai attacks, helicopter crashes.</p>', tags: ['Pink · Yellow forms'] },
  'dead-cat': { label: 'Identification of Dead Body — by State', info: '<p><strong>Recently dead (&lt; 24 h):</strong></p><ul><li>Visual recognition still possible</li><li>Fingerprints + personal effects + face easy to use</li><li>DNA from any tissue</li></ul><p><strong>Decomposed:</strong></p><ul><li>Visual recognition unreliable</li><li>Fingerprints — if hand skin preserved (may need glove technique)</li><li>Dental records · DNA from deep tissue / bone marrow</li></ul><p><strong>Skeletal remains:</strong></p><ul><li>Bone DNA (femur shaft, teeth — petrous temporal bone best)</li><li>Dental records</li><li>Superimposition technique · facial reconstruction</li><li>Ossification + dentition for age estimation</li></ul><p>★ <strong>Charred bodies:</strong> Dental + DNA from femur bone marrow are most reliable.</p>', tags: ['Recent · Decomposed · Skeletal'] },
  'superimposition': { label: 'Superimposition Technique', info: '<p><strong>Method:</strong> Antemortem photograph of suspected individual is photographically / digitally superimposed on the skull image.</p><p>If <strong>anatomical landmarks</strong> align — orbits, nasal aperture, position of teeth, mandible contour — positive identification is established.</p><p><strong>Process:</strong></p><ol><li>Skull photographed under controlled lighting / angle</li><li>AM photograph scaled to same size</li><li>Overlaid digitally</li><li>Check landmark concordance</li></ol><p>★ Used in famous Indira Gandhi assassins identification case (1984).</p>', tags: ['Skull + photo overlay'] },

  'sex-evidence': { label: 'Sex Determination — 3 Levels of Evidence', info: '<ol><li><strong>Presumptive</strong> — external appearance, clothing, body contour, hair distribution, voice, inclinations<br>(Difficulty if person tries to conceal/transgender)</li><li><strong>Probable</strong> — secondary sex characteristics (breasts, genitals, hair pattern, subcutaneous fat, muscular development)<br>(Difficulty in intersex / ambiguous conditions)</li><li><strong>Positive</strong><ul><li>Presence of ovaries (♀) or testes (♂)</li><li>Barr bodies / Davidson bodies (microscopic)</li><li>Karyotyping (XX vs XY)</li></ul></li></ol><p>Sex must be established in living, dead, and skeletal remains.</p>', tags: ['Presumptive → Probable → Positive'] },
  'sex-physical': { label: 'Male vs Female — Physical Features', info: '<table><tr><th>Feature</th><th>♂ Male</th><th>♀ Female</th></tr><tr><td>Built / weight</td><td>Muscular, taller, heavier</td><td>Less muscular, delicate, lighter</td></tr><tr><td>Scalp hair</td><td>Short, coarse</td><td>Long, fine</td></tr><tr><td>Beard / moustache</td><td>Present</td><td>Absent / rudimentary</td></tr><tr><td>Voice (post-puberty)</td><td>Hoarse</td><td>Soft</td></tr><tr><td>Body hair</td><td>Chest, abdomen, limbs</td><td>Insignificant</td></tr><tr><td>Pubic hair</td><td>Diamond, extends to navel</td><td>Triangular, on mons pubis</td></tr><tr><td>Breast</td><td>Rudimentary</td><td>Well developed</td></tr><tr><td>Thyroid cartilage angle</td><td>&lt; 90° (prominent)</td><td>&gt; 120° (less prominent)</td></tr><tr><td>Shoulder vs hip</td><td>Shoulder &gt; hip</td><td>Hip &gt; shoulder</td></tr><tr><td>Gluteal</td><td>Flat</td><td>Full, roundish</td></tr><tr><td>Wrist/ankle</td><td>Coarse, rough</td><td>Smooth, delicate</td></tr></table>', tags: ['Morphological comparison'] },
  'sex-micro': { label: 'Microscopic / Chromosomal Methods', info: '<p><strong>BARR BODY (sex chromatin):</strong></p><ul><li>Inactivated X chromosome → basophilic, condensed mass</li><li>Located near inner surface of nuclear membrane in somatic cells</li><li>Present in FEMALES (XX); absent in males (XY)</li><li>Female = "chromatin positive"</li><li>Found in buccal mucosa smear, skin, cartilage, amniotic fluid</li></ul><p><strong>DAVIDSON BODY (drumstick):</strong></p><ul><li>Additional lobe on female neutrophil nucleus (1.5 µm)</li><li>Dense chromatin head attached by thin filament</li><li>Need ≥ 6% count in peripheral smear to confirm female</li><li>Stains: Leishman, Giemsa</li></ul><p><strong>KARYOTYPING:</strong></p><ul><li>Cell culture + colchicine (arrests mitosis at metaphase)</li><li>Definitive XX vs XY</li></ul><p><strong>Y-chromosome detection:</strong> Quinacrine / acridine stain + fluorescence microscope.</p>', tags: ['Barr + Davidson + karyotype'] },
  'sex-pelvis': { label: 'Pelvis — Most Reliable Sex Bone (95%)', info: '<table><tr><th>Feature</th><th>Male</th><th>Female</th></tr><tr><td><strong>Sub-pubic angle</strong></td><td>&lt; 90° (typically 50-60°)</td><td>&gt; 90° (typically 85-100°) ★ NEET-PG 2016 Q14</td></tr><tr><td>Sciatic notch</td><td>Narrow, deep</td><td>Wide, shallow (&gt; 60°)</td></tr><tr><td>Pelvic brim</td><td>Heart-shaped (android)</td><td>Oval, round (gynaecoid)</td></tr><tr><td>Pelvic cavity</td><td>Deep, narrow</td><td>Shallow, capacious</td></tr><tr><td>Sacrum</td><td>Long, narrow, more curved</td><td>Short, wide, less curved</td></tr><tr><td>Obturator foramen</td><td>Oval</td><td>Triangular</td></tr><tr><td>Acetabulum</td><td>Larger, faces laterally</td><td>Smaller, faces forward</td></tr></table><p>Accuracy: pelvis alone ~ 95%.</p>', tags: ['PYQ 2016 Q14', 'Subpubic 85° = ♀'] },
  'sex-skull': { label: 'Skull — Second-Best Sex Bone (92%)', info: '<ul><li><strong>Male skull:</strong> larger, heavier · supraorbital ridges prominent · forehead sloping · mastoid large · zygomatic process robust · external occipital protuberance pronounced</li><li><strong>Female skull:</strong> smaller, lighter · ridges smooth · forehead vertical · mastoid small · zygomatic process slender · occipital protuberance flat</li><li><strong>Mandible:</strong> ♂ square chin, ramus angle &lt; 125° · ♀ rounded chin, ramus angle &gt; 125°</li></ul><p>Accuracy: skull alone ~ 92%; pelvis + skull combined ~ 98%.</p>', tags: ['92% alone'] },
  'sex-other': { label: 'Other Skeletal Sex Markers', info: '<ul><li><strong>Sternum:</strong> ♂ length of manubrium &gt; ½ length of body of sternum</li><li><strong>Long bones:</strong> ♂ longer + thicker · ♀ smaller condyles</li><li><strong>Femur head diameter:</strong> ♂ ≥ 48 mm · ♀ ≤ 43 mm (cut-off varies by population)</li><li><strong>Clavicle, scapula:</strong> ♂ longer, heavier</li><li><strong>Humerus head diameter:</strong> ♂ ≥ 46 mm</li><li><strong>DNA from bone:</strong> amelogenin gene (AMELX 106 bp, AMELY 112 bp) — definitive</li></ul>', tags: ['Long bone metrics'] },

  'age-categories': { label: 'Age Estimation — 4 Categories', info: '<ol><li><strong>Foetus</strong> — somite count, length, weight, morphology, USG, ossification centres</li><li><strong>Children &amp; adolescents</strong> — dentition + ossification + Tanner staging + anthropometry</li><li><strong>Adults (&gt; 25 yr)</strong> — Gustafson\'s method (teeth) + skeletal/skin changes + sternum + clavicle</li><li><strong>Dead body / skeletal remains</strong> — bones (ossification + epiphyseal fusion) + teeth + secondary changes (lipping, suture closure)</li></ol>', tags: ['Foetus → Child → Adult → Skeletal'] },
  'age-foetus': { label: 'Foetal Age Estimation', info: '<p><strong>Haase formula:</strong></p><ul><li>Up to 5 months: Length (cm) = age (months)² ; OR age = √length</li><li>After 5 months: Length / 5 = age in months</li></ul><p><strong>Other landmarks:</strong></p><ul><li>Quickening — 4 months IUL</li><li>Viability — 7 months IUL (legal threshold for foeticide)</li><li>Crown-rump length (CRL) on USG</li></ul><p><strong>Ossification centres:</strong></p><ul><li>Calcaneum, talus, cuboid — at birth (term)</li><li>Distal femur ossifies in utero — proves full-term foetus</li><li>Proximal tibia — appears shortly before birth</li></ul>', tags: ['Haase formula'] },
  'age-child': { label: 'Children — Primary Age Methods', info: '<ul><li><strong>Dentition</strong> — eruption sequence (primary 6 mo - 2 yr; permanent 6-25 yr)</li><li><strong>Ossification centres</strong> — appearance + fusion (wrist + elbow + shoulder X-ray combinations)</li><li><strong>Anthropometry</strong> — height, weight, head circumference (compared with growth charts)</li><li><strong>Tanner staging (sexual maturity rating, SMR)</strong>:<ul><li>T1 — prepubertal · T2 — early pubertal</li><li>T3 — mid-pubertal · T4 — advanced</li><li>T5 — adult</li></ul></li><li>Useful for 9-18 yr age estimation</li><li>★ Combine dental + ossification for best accuracy</li></ul>', tags: ['Tanner T1-T5'] },
  'age-adult': { label: 'Adults &gt; 25 yr — Age Methods', info: '<ul><li><strong>Gustafson\'s method</strong> (teeth, 6 parameters) — gold standard for adults</li><li><strong>Miles method</strong> — root translucency alone</li><li><strong>Biochemical</strong> — aspartic acid racemisation</li><li><strong>Skeletal changes</strong>:<ul><li>Lipping of lumbar vertebrae 40-50 yr</li><li>Calcification of thyroid / cricoid / hyoid 40+ yr</li><li>Atrophic intervertebral discs 50-60 yr</li><li>Xiphoid-sternum fusion ~ 40 yr</li><li>Manubrium-body sternum fusion ~ 60 yr</li><li>Sternal rib end changes (calcification + shape)</li></ul></li><li><strong>Skin changes</strong>: wrinkles, dry skin, ecchymoses, arcus senilis, cataract, presbyopia, graying, baldness</li></ul>', tags: ['Gustafson + skeletal'] },
  'age-legal': { label: 'Medicolegal Importance of Different Ages', info: '<table><tr><th>Age</th><th>Significance</th></tr><tr><td>4 mo IUL</td><td>Quickening</td></tr><tr><td>7 mo IUL</td><td>Viability</td></tr><tr><td>&lt; 1 yr</td><td>Killing = infanticide (BNS / IPC)</td></tr><tr><td>5 yr</td><td>Half fare railway · admission first standard</td></tr><tr><td>&lt; 7 yr</td><td>NO criminal responsibility (IPC 82 / BNS equivalent) ★</td></tr><tr><td>7-12 yr</td><td>Limited criminal responsibility if sufficient maturity (IPC 83)</td></tr><tr><td>&lt; 12 yr</td><td>Cannot give consent for medical exam (IPC 89) · oath not necessary</td></tr><tr><td>&lt; 14 yr</td><td>Cannot be employed in factories (Factories Act 1948)</td></tr><tr><td>&lt; 15 yr</td><td>Sex with wife &lt; 15 yr = punishable</td></tr><tr><td>16 yr</td><td>Age of consent for sex (POCSO override now 18 yr)</td></tr><tr><td>18 yr</td><td>Majority · voting · marriage (♀) · medical consent</td></tr><tr><td>21 yr</td><td>Marriage (♂) · majority under court guardianship</td></tr><tr><td>25 yr</td><td>State Assembly candidate</td></tr><tr><td>30 yr</td><td>Parliament candidate</td></tr><tr><td>35 yr</td><td>President / VP / Governor candidate</td></tr><tr><td>60-65 yr</td><td>Govt retirement · senior citizen</td></tr></table>', tags: ['Legal milestones'] },

  'teeth-overview': { label: 'Dentition Overview', info: '<p><strong>Primary (temporary / milk / deciduous) dentition:</strong> 20 teeth total — 8 incisors + 4 canines + 8 molars (no premolars).</p><p><strong>Permanent dentition:</strong> 32 teeth total — 8 incisors + 4 canines + 8 premolars + 12 molars.</p><p><strong>Per half-jaw (¼ of mouth):</strong></p><ul><li>Primary: 2 incisors + 1 canine + 2 molars = 5 teeth</li><li>Permanent: 2 incisors + 1 canine + 2 premolars + 3 molars = 8 teeth</li></ul>', tags: ['20 + 32'] },
  'primary-teeth': { label: 'Primary (Milk) Dentition — Eruption ★', info: '<p><strong>20 milk teeth · eruption 6 months to 2 years</strong></p><table><tr><th>Tooth</th><th>Age</th></tr><tr><td><strong>★ Lower central incisor</strong></td><td><strong>6-8 mo (FIRST!)</strong></td></tr><tr><td>Upper central incisor</td><td>7-9 mo</td></tr><tr><td>Upper lateral incisor</td><td>8-10 mo</td></tr><tr><td>Lower lateral incisor</td><td>10-12 mo</td></tr><tr><td>1st molar</td><td>12-14 mo (1 yr)</td></tr><tr><td>Canine</td><td>18 mo (1.5 yr)</td></tr><tr><td>2nd molar</td><td>24 mo (2 yr)</td></tr></table><p>★ <strong>Half-year rule:</strong> Add 6 months to type → period of eruption (incisor 6 mo → 1st molar at 1 yr → canine at 1.5 yr → 2nd molar at 2 yr).</p><p>★ <strong>NEET-PG 2016 Q15</strong>: First incisor to erupt = LOWER CENTRAL.</p><p>★ <strong>NEET-PG 2016 Q16</strong>: First milk tooth at 6 months.</p>', tags: ['PYQ 2016 Q15+Q16'] },
  'permanent-teeth': { label: 'Permanent Dentition — Eruption', info: '<p><strong>32 permanent teeth · eruption 6 years onwards</strong></p><table><tr><th>Tooth</th><th>Age</th></tr><tr><td><strong>1st molar</strong></td><td><strong>6 yr</strong> ★ first permanent</td></tr><tr><td>Central incisor</td><td>7-8 yr</td></tr><tr><td>Lateral incisor</td><td>8-9 yr</td></tr><tr><td>1st premolar</td><td>9-10 yr</td></tr><tr><td>2nd premolar</td><td>10-11 yr</td></tr><tr><td>Canine</td><td>11-12 yr</td></tr><tr><td>2nd molar</td><td>12-14 yr</td></tr><tr><td><strong>3rd molar (wisdom)</strong></td><td><strong>17-25 yr</strong> (last)</td></tr></table><p>★ Females erupt slightly earlier than males.</p>', tags: ['1st molar at 6 yr'] },
  'replacement': { label: 'Mixed Dentition — Replacement Rules', info: '<ul><li><strong>Primary incisors + canines</strong> are replaced by <strong>PERMANENT incisors + canines</strong></li><li><strong>Primary molars</strong> are replaced by <strong>PERMANENT PREMOLARS</strong> (NOT permanent molars!)</li><li><strong>At 6 yr:</strong> first permanent molars erupt BEHIND the 2nd primary molar (no primary tooth lost in this position)</li></ul><p>Mixed dentition period: roughly 6 to 12 years.</p><p>★ <strong>Most commonly absent permanent tooth = 3rd molar (wisdom)</strong>, followed by upper lateral incisor.</p><p>★ Hypodontia / supernumerary teeth — congenital anomalies.</p>', tags: ['Molars → Premolars'] },
  'gustafson': { label: 'Gustafson\'s Method ★ (Adults > 25 yr)', info: '<p><strong>Gustafson (1950)</strong> — age estimation from extracted tooth using 6 parameters, each scored 0 to 3:</p><ol><li><strong>Attrition (A)</strong> — wear on masticating surface (A0 none → A3 exposes pulp)</li><li><strong>Periodontosis (P)</strong> — exposure of root from gum recession (P0-P3)</li><li><strong>Secondary dentine (S)</strong> — deposition in pulp cavity (S0-S3)</li><li><strong>Root resorption (R)</strong> — decay / resorption of root</li><li><strong>Cementum apposition (C)</strong> — thickening with age</li><li><strong>Root transparency (T)</strong> ★ — rarefaction of dentine → SINGLE most important parameter</li></ol><p><strong>Formula:</strong> A + P + S + R + C + T = total points → compared to standard regression curve → age in years.</p><p><strong>Disadvantages:</strong> Tooth must be extracted (limited use in living); errata if poor oral hygiene; technically difficult.</p>', tags: ['6 parameters', 'Root transparency = key'] },
  'dental-other': { label: 'Other Age-from-Teeth Methods', info: '<ul><li><strong>Miles method</strong> — root translucency alone (simplified Gustafson)</li><li><strong>Biochemical (aspartic acid racemisation)</strong> — Levo amino acids convert to Dextro with age</li><li><strong>Fluorescence (Kvaal 1989)</strong> — intensity in dentine + cementum increases with age</li><li><strong>Radiographic</strong> — pulp/crown ratio decreases (Kvaal, Cameriere)</li><li><strong>Boyde\'s neonatal line</strong> — separates pre- from post-natal enamel · proves live birth</li><li><strong>Hutchinson teeth</strong> — notched permanent incisors → congenital syphilis</li><li><strong>Mulberry molars</strong> — dome-shaped molars → congenital syphilis</li></ul>', tags: ['Miles · Kvaal · Hutchinson'] },

  'ossif-overview': { label: 'Ossification Centres — Forensic Use', info: '<p>Bones develop from one or more <strong>OSSIFICATION CENTRES</strong> at characteristic ages.</p><p><strong>Two stages:</strong></p><ul><li><strong>Appearance (A)</strong> — primary or secondary centre becomes visible on X-ray</li><li><strong>Fusion (F)</strong> — epiphysis fuses with diaphysis (closes growth plate)</li></ul><p><strong>X-ray combinations</strong> for age estimation:</p><ul><li>Wrist X-ray — carpals + distal radius/ulna (best for 0-18 yr)</li><li>Elbow X-ray — distal humerus + proximal radius/ulna (6-15 yr)</li><li>Shoulder X-ray — proximal humerus + glenoid (12-22 yr)</li></ul><p>★ <strong>Females ossify ~ 1-2 yr earlier than males.</strong></p>', tags: ['A vs F', 'Wrist + elbow + shoulder'] },
  'carpal': { label: 'Carpal Bones — Appearance Sequence ★', info: '<p>8 carpal bones appear in sequence:</p><ol><li><strong>Capitate</strong> — 1-3 months</li><li><strong>Hamate</strong> — 2-4 months</li><li><strong>Triquetral</strong> — 2-3 years</li><li><strong>Lunate</strong> — 3-5 years</li><li><strong>Trapezium</strong> — 4-6 years</li><li><strong>Trapezoid</strong> — 4-7 years</li><li><strong>★ SCAPHOID</strong> — 4-7 years (NEET-PG 2016 Q13 verbatim)</li><li><strong>★ PISIFORM</strong> — 9-12 years (LAST to appear — unique sesamoid bone)</li></ol><p><strong>Mnemonic:</strong> "Come, Here To Take Tea, Sip Please" (Capitate → Hamate → Triquetral → Trapezium → Trapezoid → Scaphoid → Pisiform; Lunate fits in chronologically between Triquetral and Trapezium)</p>', tags: ['PYQ 2016 Q13', 'Pisiform last'] },
  'long-bones': { label: 'Long Bone Epiphyseal Fusion', info: '<p>Key fusion dates (♀ ~ 1-2 yr earlier than ♂):</p><ul><li><strong>Femur head:</strong> F 14-15 yr (♀) · 16-17 yr (♂)</li><li><strong>Greater trochanter:</strong> F 14 yr (♀) · 17 yr (♂)</li><li><strong>Distal femur:</strong> Appears BEFORE BIRTH; fuses 14-17 yr</li><li><strong>Proximal tibia:</strong> Appears shortly before birth; fuses 14-17 yr</li><li><strong>Distal radius/ulna:</strong> F 17-19 yr (♀) · 19-20 yr (♂)</li><li><strong>Iliac crest:</strong> F 17-19 yr (♀) · 19-20 yr (♂)</li><li><strong>Medial end clavicle:</strong> F 20-22 yr — ★ LAST major bone to fuse</li><li><strong>Triradiate cartilage</strong> (acetabulum): disappears 13-14 yr (♀) · 15-16 yr (♂)</li><li><strong>Ischio-pubic ramus:</strong> F 8.5 yr</li><li><strong>Patella:</strong> A 3-4 yr (♀) · 3-7 yr (♂)</li></ul>', tags: ['Clavicle last'] },
  'tarsals': { label: 'Tarsal Bones (Foot)', info: '<p>Of 7 tarsals, three are present <strong>AT BIRTH</strong>:</p><ul><li><strong>Calcaneum</strong> — at birth (3rd month IUL)</li><li><strong>Talus</strong> — at birth (6-7th month IUL)</li><li><strong>Cuboid</strong> — at birth (9th month IUL)</li></ul><p>★ Presence of these 3 proves <strong>near-term foetus</strong> or live birth.</p><p>Other tarsals appear later: cuneiforms 1-4 yr · navicular 1-4 yr.</p><p>★ <strong>Distal end of femur</strong> also ossifies BEFORE birth → indicates <strong>full-term infant</strong> (important in infanticide cases).</p>', tags: ['3 at birth'] },
  'ossif-skull': { label: 'Skull Sutures &amp; Fontanelles', info: '<p><strong>Fontanelles:</strong></p><ul><li>Anterior fontanelle — closes 18-24 months (~ 2 yr)</li><li>Posterior fontanelle — closes 2-3 months</li></ul><p><strong>Sutures:</strong></p><ul><li>Metopic (mid-frontal) — closes 3-8 yr (may remain open as "metopism")</li><li>Sagittal — closes 30-40 yr (inside-out)</li><li>Coronal — closes 38-50 yr</li><li>Lambdoid — closes 45-50 yr</li></ul><p>★ Skull suture closure is variable — gives only rough age estimate (± 5-10 yr) in adults. Combine with other methods.</p>', tags: ['Variable in adults'] },
  'sternum': { label: 'Sternum + Vertebrae', info: '<p><strong>Sternum:</strong></p><ul><li>Manubrium ossifies in utero</li><li>Body of sternum: 4 segments fuse 14-25 yr</li><li>Xiphoid: appears 3 yr; fuses with body of sternum at ~ <strong>40 yr</strong></li><li>Manubrium-body fusion: ~ <strong>60 yr</strong></li></ul><p><strong>Vertebrae:</strong></p><ul><li>Vertebral body + arches fuse 3-6 yr</li><li>Ring epiphyses (superior + inferior surfaces) fuse 25 yr</li><li>Tip of spinous + transverse processes fuse 25 yr</li></ul>', tags: ['Xiphoid 40 yr · M-B 60 yr'] },
  'combined-xray': { label: 'X-Ray Combinations by Age Group', info: '<ul><li><strong>0-5 yr:</strong> Carpal X-ray (capitate → lunate appearance) + dentition</li><li><strong>5-15 yr:</strong> Wrist X-ray (carpals + distal radius epiphysis) + dentition (mixed dentition)</li><li><strong>15-25 yr:</strong> Wrist + elbow + shoulder X-rays (long-bone epiphyseal fusion) + 3rd molar eruption</li><li><strong>&gt; 25 yr:</strong> Gustafson + skeletal changes (lipping, calcifications) + medial clavicular epiphysis</li><li><strong>Skeletal remains:</strong> All available bones + teeth combined</li></ul><p>★ Always state age estimate with uncertainty (± 1-2 yr in children, ± 3-5 yr in adults).</p>', tags: ['Age-specific X-rays'] },

  'stature-def': { label: 'Stature — Definition &amp; General Rules', info: '<p><strong>Stature</strong> = body height of a person.</p><p><strong>Growth pattern:</strong></p><ul><li>Increases from IUL up to ~ 21 yr (♂), ~ 17 yr (♀)</li><li>Maximum between 20-25 yr</li><li>After 25 yr → decreases ~ 1 mm/year</li></ul><p><strong>Diurnal variation:</strong></p><ul><li>HIGHER in morning + recumbent position</li><li>LOWER in evening (disc compression) + standing</li></ul><p><strong>In dead body:</strong> may LENGTHEN by 2-3 cm in primary relaxation; SHORTER in rigor mortis.</p>', tags: ['↓ 1 mm/yr after 25'] },
  'stature-formulae': { label: 'Body Part Formulae for Stature', info: '<ol><li><strong>Arm span:</strong> distance between tips of middle fingers of overstretched arms ≈ STATURE</li><li><strong>Vertex to symphysis pubis × 2</strong> = stature</li><li><strong>One upper limb × 2 + 34 cm</strong> (34 cm = 2 clavicles + manubrium width)</li><li><strong>Sternal notch to symphysis pubis × 3.3</strong></li><li><strong>Forearm × 3.7</strong> (fingertip to tip of olecranon)</li><li><strong>Head length × 7</strong> (top of head to tip of chin)</li><li><strong>Vertebral column × 35/100</strong></li><li><strong>Hand length</strong> (Bhatnagar 1984): Stature = 127.97 + 2.06 × hand length</li></ol>', tags: ['Multiple formulae'] },
  'stature-bone': { label: 'Bone-Based Regression Formulae', info: '<p><strong>Karl Pearson (1899):</strong></p><ul><li>Regression equations from femur, tibia, humerus, radius</li><li>e.g. ♂ Stature = 81.31 + 1.88 × femur length (cm)</li><li>♀ Stature = 72.84 + 1.94 × femur length (cm)</li></ul><p><strong>Trotter &amp; Gleser (1952, 1958):</strong></p><ul><li>Most widely used; race + sex-specific</li><li>e.g. ♂ White: 64.42 + 2.32 × femur (± 3.94 cm SE)</li><li>♀ Black: 28.6 + 2.34 × femur (± 3.4 cm)</li></ul><p><strong>Indian formulae:</strong></p><ul><li>Pan (1924) · Singh &amp; Sohal · Pheasant (1986) · Nat (1931)</li><li>Used by Indian forensic labs for skeletal cases</li></ul>', tags: ['Pearson · Trotter-Gleser'] },
  'stature-foot': { label: 'Footprints &amp; Foot Length', info: '<p><strong>Stature ≈ 6 × foot length</strong> (rough estimate; varies by population)</p><p><strong>Footprint analysis:</strong></p><ul><li>Length, width, ridge characteristics</li><li>Dermatoglyphics of foot are individual (like fingerprints)</li><li>Bare footprint at scene → measure heel-to-toe length</li></ul><p><strong>Shoe prints:</strong></p><ul><li>Make, model, size from manufacturer database</li><li>Wear pattern reveals gait, occupation, posture</li></ul><p>★ Useful at crime scene + temple footprints (religious significance).</p>', tags: ['Stature = 6 × foot'] },
  'stature-skel': { label: 'Stature from Skeletal Remains', info: '<ul><li>★ <strong>Femur</strong> = most reliable single bone</li><li>★ Combined long bones (femur + tibia + humerus + radius) give highest accuracy</li><li><strong>Vertebral column:</strong> Stature = vertebral column length × 35/100</li><li>★ If only fragments available — use any long bone with appropriate formula</li><li>★ Hand / foot / single phalanx — less accurate but possible</li><li><strong>Sex must be determined first</strong> (different regression equations)</li></ul>', tags: ['Femur best'] },
  'stature-variations': { label: 'Diurnal &amp; Postmortem Variations', info: '<p><strong>HIGHER stature:</strong></p><ul><li>20-25 yr (peak)</li><li>Morning hours (before disc compression)</li><li>Recumbent position</li><li>Primary relaxation in dead body (lengthens 2-3 cm)</li></ul><p><strong>LOWER stature:</strong></p><ul><li>Evening (after day of weight-bearing → disc compression)</li><li>Standing position</li><li>Rigor mortis phase in dead body</li></ul><p><strong>After 25 yr:</strong> stature decreases ~ 1 mm per year (cumulative loss of intervertebral disc height + kyphosis).</p>', tags: ['Diurnal · postmortem'] },

  'race-def': { label: 'Race — Definition', info: '<p><strong>Race</strong> = biological grouping within the human species distinguished or classified according to <strong>GENETICALLY TRANSMITTED DIFFERENCES</strong>.</p><p>Race is a POPULATION concept — populations differing in the frequency of some genes.</p><p>World population is conventionally divided into 3 racial groups:</p><ol><li><strong>Caucasoid</strong> — Europeans, West Asians, Indians (subset)</li><li><strong>Mongoloid</strong> — East Asians, Native Americans</li><li><strong>Negroid</strong> — Sub-Saharan Africans</li></ol><p>★ <strong>Modern forensics is moving away from rigid 3-race classification</strong> toward geographic ancestry estimation using DNA SNPs (single nucleotide polymorphisms).</p>', tags: ['3 broad groups'] },
  'caucasoid': { label: 'Caucasoid — Features', info: '<ul><li><strong>Complexion:</strong> Fair</li><li><strong>Iris colour:</strong> Gray or blue (often)</li><li><strong>Hair:</strong> Straight or wavy, blonde/brown/fair · 70-100 µm · oval cross-section · uniform pigment</li><li><strong>Forehead:</strong> RAISED</li><li><strong>Nose:</strong> Sharp · nasal aperture narrow + elongated</li><li><strong>Face:</strong> Small</li><li><strong>Hard palate:</strong> TRIANGULAR</li><li><strong>Limbs:</strong> Normal proportions</li><li><strong>Skull:</strong> Dolichocephalic (long-headed); cephalic index &lt; 75</li></ul>', tags: ['Triangular palate'] },
  'mongoloid': { label: 'Mongoloid — Features', info: '<ul><li><strong>Complexion:</strong> Yellowish</li><li><strong>Iris:</strong> Black</li><li><strong>Hair:</strong> Coarse, straight/wavy, black/brown · 90-120 µm · ROUND cross-section · dense pigment · thick cuticle</li><li><strong>Forehead:</strong> Inclined backward</li><li><strong>Nose:</strong> Flattened · nasal aperture rounded</li><li><strong>Face:</strong> Large + flattened (high cheekbones)</li><li><strong>Hard palate:</strong> LARGE &amp; FLATTENED</li><li><strong>Upper / lower limbs:</strong> Small</li><li><strong>Skull:</strong> Brachycephalic (round); cephalic index &gt; 80 · epicanthic fold of eyes</li></ul>', tags: ['Round skull · flat palate'] },
  'negroid': { label: 'Negroid — Features', info: '<ul><li><strong>Complexion:</strong> Black</li><li><strong>Iris:</strong> Black</li><li><strong>Hair:</strong> Thick, woolly, curly, self-spiraled · 60-90 µm · FLATTENED cross-section · dense clumped pigment toward periphery</li><li><strong>Forehead:</strong> Small + compressed</li><li><strong>Nose:</strong> Blunt · nasal aperture BROAD</li><li><strong>Face:</strong> Jaw projects forward (prognathism) · teeth set obliquely · malar (cheek) bones prominent</li><li><strong>Hard palate:</strong> RECTANGULAR</li><li><strong>Upper limbs:</strong> Long; forearm long compared to arm; hand small</li><li><strong>Lower limbs:</strong> Leg long compared to thigh; feet wide and flat; heel bone projects backward</li></ul>', tags: ['Rectangular palate · prognathism'] },
  'cephalic-index': { label: 'Cephalic Index', info: '<p><strong>Formula:</strong> (max breadth of skull / max length) × 100</p><p><strong>Categories:</strong></p><ul><li><strong>Dolichocephalic (long-headed):</strong> &lt; 75 — Caucasoid, Negroid, Pure Aryans</li><li><strong>Mesocephalic (medium):</strong> 75-80 — many Europeans, average Indian</li><li><strong>Brachycephalic (round-headed):</strong> &gt; 80 — Mongoloid, some Europeans</li><li><strong>Hyperbrachycephalic:</strong> &gt; 85 — some populations</li></ul><p>Used for race classification + ethnic ancestry estimation.</p>', tags: ['(B/L) × 100'] },
  'other-indices': { label: 'Other Anthropometric Indices', info: '<ul><li><strong>Nasal index</strong> = (nasal width / height) × 100<ul><li>Leptorrhine &lt; 70 (narrow nose) — Caucasoid</li><li>Mesorrhine 70-85 — intermediate</li><li>Platyrrhine &gt; 85 (broad nose) — Negroid</li></ul></li><li><strong>Orbital index</strong> = (orbital height / breadth) × 100<ul><li>Megaseme &gt; 89 — Mongoloid · Microseme &lt; 83 — Negroid</li></ul></li><li><strong>Facial index</strong> = (face length / breadth) × 100<ul><li>Leptoprosopic (long face) vs Euryprosopic (broad face)</li></ul></li></ul>', tags: ['Nasal · Orbital · Facial'] },

  'fp-def': { label: 'Fingerprints — Definition &amp; Synonyms', info: '<p><strong>Synonyms:</strong> Dactylography · Dermatoglyphics · Galton system of identification.</p><p><strong>Definition:</strong> Fingerprints are impressions of patterns formed by the <strong>PAPILLARY (epidermal) RIDGES</strong> of the fingertips.</p><p><strong>Principle:</strong> Individual peculiarities of the patterns formed by the arrangement of papillary ridges are <strong>ABSOLUTELY CONSTANT</strong> and persist throughout life from infancy to old age, and the patterns of no two hands resemble each other.</p>', tags: ['Galton system'] },
  'fp-features': { label: 'Fingerprint Features — Key Pearls ★', info: '<ul><li>★ <strong>Identification by this system is ABSOLUTE</strong></li><li>★ Highly individualistic <strong>EVEN IN MONOZYGOTIC TWINS</strong> (NEET-PG 2019 Q5)</li><li>★ Form during <strong>INTRA-UTERINE LIFE</strong>:<ul><li>Primary epidermal ridges appear at 2-3 month IUL</li><li>Secondary ridges develop by 5th month</li><li>Fully formed and permanent by 24 weeks IUL</li></ul></li><li>★ Chance of two persons having identical fingerprints: <strong>1 in 64 billion</strong></li><li>★ Follow <strong>Quetelet\'s rule</strong> — "all nature-made things have unlimited and infinite variations of forms"</li><li>Survive injury (skin regenerates same pattern)</li><li>Lost only with deep dermal scarring or 4th degree burn</li></ul>', tags: ['PYQ 2019 Q5'] },
  'fp-types': { label: 'Galton Classification — 4 Types', info: '<table><tr><th>Type</th><th>%</th><th>Sub-types</th></tr><tr><td>Loop</td><td><strong>65%</strong> ★</td><td>Ulnar loop (opens toward little finger) · Radial loop (opens toward thumb)</td></tr><tr><td>Whorl</td><td>25%</td><td>Concentric · spiral CW · spiral CCW · double spiral · almond shape</td></tr><tr><td>Arch</td><td>7%</td><td>Plain · tented · exceptional</td></tr><tr><td>Composite</td><td>2-3% ★ rarest</td><td>Central pocket loop · twined loop · accidental</td></tr></table><p>★ <strong>Mnemonic:</strong> "Loops Wear Aprons Carelessly" — Loop &gt; Whorl &gt; Arch &gt; Composite by frequency.</p>', tags: ['Loop &gt; Whorl &gt; Arch &gt; Composite'] },
  'fp-recording': { label: 'Fingerprint Recording Methods', info: '<p><strong>PLAIN method:</strong></p><ul><li>Inked finger pressed directly onto unglazed paper</li><li>Advantages: quick, easy</li><li>Disadvantage: smaller area for comparison</li></ul><p><strong>ROLLED method:</strong></p><ul><li>Finger rolled outward → inward on paper without lifting</li><li>Advantage: gives larger surface area</li><li>Disadvantage: more difficult; may blur</li></ul><p><strong>Comparison criteria:</strong></p><ul><li>★ <strong>16-20 matching points</strong> = positive ID (Indian forensic standard)</li><li>Compare ridge endings · pattern · delta · core · island · fork · bifurcation · ridge count</li></ul>', tags: ['Plain · Rolled · 16-20 match'] },
  'fp-scene': { label: 'Crime Scene Fingerprints — 3 Types', info: '<ol><li><strong>VISIBLE prints</strong> — fingers smeared with blood, paint, oil, grease, dust, secretions → directly visible to naked eye</li><li><strong>PLASTIC prints</strong> — on soft surfaces (soap, wax, clay, cheese, putty) → 3-D impression</li><li><strong>LATENT prints</strong> ★ — invisible or barely visible<ul><li>From sebaceous + sweat gland secretions</li><li>Need REAGENTS to develop:<ul><li><strong>Powders</strong> — aluminium, black, magnetic</li><li><strong>Chemicals</strong> — ninhydrin (purple, amino acids), cyanoacrylate fuming, silver nitrate, iodine</li></ul></li><li><strong>"Chance fingerprints"</strong> — accidental latent prints, the most common at crime scene</li></ul></li></ol>', tags: ['Visible · Plastic · Latent'] },
  'fp-uses': { label: 'Medicolegal Uses of Fingerprints', info: '<ul><li>Identification of unknown bodies in disaster, decomposition</li><li>Habitual criminals — NCRB AFIS (Automated Fingerprint Identification System) database</li><li>Aadhaar (UIDAI) — biometric national ID</li><li>Disputed identity / paternity (combined with DNA)</li><li>Documents — signature comparison, forgery detection</li><li>Crime scene reconstruction — placing suspect at scene</li><li>Hospital newborn footprint records — preventing baby interchange</li></ul>', tags: ['AFIS · Aadhaar · crime scene'] },
  'fp-history': { label: 'History of Fingerprint Identification', info: '<ul><li><strong>Henry Faulds (1880)</strong> — first to propose fingerprints for criminal identification</li><li><strong>Sir William Herschel</strong> — used in India (Hooghly) for civil contracts</li><li><strong>Sir Francis Galton (1892)</strong> — "Finger Prints" book; classified into types ★</li><li><strong>Juan Vucetich (1892, Argentina)</strong> — first criminal conviction based on fingerprint</li><li><strong>Sir Edward Henry (1897)</strong> — developed Henry classification at Bengal Police</li><li><strong>India</strong> — first FP bureau established at Calcutta 1897 (Khan Bahadur Azizul Haque, Hem Chandra Bose worked under Henry)</li></ul>', tags: ['Galton 1892'] },

  'tattoo-def': { label: 'Tattoo Marks — Definition &amp; Dyes', info: '<p><strong>Definition:</strong> Designs effected by multiple small puncture wounds through the skin with needles dipped in colouring material (dye).</p><p><strong>Dyes used:</strong></p><table><tr><th>Dye</th><th>Colour</th></tr><tr><td>Carbon (India ink) / China ink / Soot</td><td>BLACK</td></tr><tr><td>Cinnabar / Vermilion</td><td>RED</td></tr><tr><td>Ochre</td><td>BROWN</td></tr><tr><td>Chromic oxide</td><td>GREEN</td></tr><tr><td>Prussian blue (ferric ferrocyanide), Indigo, Cobalt, Ultramarine</td><td>BLUE</td></tr></table><p><strong>Persistence:</strong> Usually distinct up to ~ 10 years; parts protected by clothes retain dye longer than exposed parts (e.g., hands/forearms fade faster).</p><p>Dyes such as vermilion or ultramarine disappear earlier than India ink.</p>', tags: ['India ink · vermilion · Prussian blue'] },
  'tattoo-reveal': { label: 'Revealing Faded Tattoos ★', info: '<p>Latent (faded) tattoos can be revealed by:</p><ol><li><strong>UV light</strong> (filtered)</li><li><strong>Infrared photography</strong></li><li>Rubbing the area + examining under magnifying glass</li><li>If obscured by decomposition → treat with <strong>3% H₂O₂</strong></li><li>Treatment with <strong>0.5% caustic potash (KOH)</strong></li><li>★ <strong>EXAMINE REGIONAL LYMPH NODES</strong> — pigment deposits in lymph nodes draining the tattoo area (NEET-PG 2020 Q3 verbatim)</li><li>Histological examination of regional lymph node tissue</li></ol><p><strong>Complications of tattooing:</strong> Infection (septic inflammation, abscess, HIV/HBV/HCV spread), scar / keloid formation.</p>', tags: ['PYQ 2020 Q3', 'Lymph node'] },
  'scars': { label: 'Scars — Definition &amp; Forensic Use', info: '<p><strong>Scar</strong> = fibrous tissue produced as a result of healing of wound, covered by epithelium DEVOID of hair follicles, sweat glands, or pigment.</p><p><strong>Features:</strong></p><ul><li>Permanent · cannot be erased completely</li><li>Damage to epidermis alone does NOT produce scar — injury to DERMIS required</li><li>Scar assumes shape of original wound:<ul><li>Incised → linear · Lacerated → broad, irregular</li><li>Stab → oval, elliptical, triangular (depending on weapon)</li><li>Burns / corrosives → irregular, coarse</li><li>Vaccination → circular, oval, flat or slightly elevated</li><li>Bullet → circular, depressed</li><li>Striae gravidarum → multiple, over abdomen (past pregnancy)</li></ul></li></ul><p><strong>Age of scar:</strong> &lt; 2 wk red + tender + scab · 2 wk-2 mo denser brown · 2-3 mo white + glistening + wrinkled.</p>', tags: ['Permanent · shape of wound'] },
  'deformities': { label: 'Deformities — Congenital + Acquired', info: '<p><strong>A. Congenital:</strong></p><ul><li>Cleft palate · hare lip (cleft lip)</li><li>Polydactyly · syndactyly · webbed fingers</li><li>Claw hand · birthmark (naevi) · moles</li><li>Kyphosis (hump back) · port wine stain</li><li>Mongolian spots · Hutchinson teeth (syphilis)</li><li>Supplementary mammae · Heterochromia iridis</li></ul><p><strong>B. Acquired:</strong></p><ul><li>Poliomyelitis sequelae · contracture · paralysis</li><li>Mal-united or non-united fractures</li><li>Old amputations · surgical scars</li><li>Occupation marks (callus, dye stains)</li><li>Cosmetic surgery scars</li></ul><p>Deformities are <strong>secondary identifiers</strong> useful when no primary identification is available.</p>', tags: ['Congenital + Acquired'] },
  'anthropometry': { label: 'Anthropometry (Bertillon System)', info: '<p><strong>Bertillon system (1879, France)</strong> — historical system of body measurement for identification.</p><p><strong>Principle:</strong></p><ol><li>After 21 yr, body part measurements DO NOT alter significantly</li><li>The ratio of body part sizes varies considerably between individuals</li></ol><p><strong>Records:</strong></p><ul><li><strong>Descriptive data:</strong> iris colour, hair, complexion, shape of nose/chin/ears, photograph (full face + right profile)</li><li><strong>Body marks:</strong> moles, birthmarks, tattoo marks, scars</li><li><strong>Body measurements (11):</strong> standing height, sitting height, head length + width, ear length + width, span of outstretched arms, length of left middle + little finger, left forearm + hand, left foot</li></ul><p><strong>Drawbacks:</strong></p><ul><li>Applicable only to adults (after age 21)</li><li>Subjective error in measurements</li><li>Requires trained personnel + instruments</li></ul><p>★ <strong>Now REPLACED by fingerprint + DNA system</strong> due to subjective errors.</p>', tags: ['Historical · replaced by FP'] },
  'posthumous': { label: 'Posthumous Child ★', info: '<p><strong>Definition:</strong> A child <strong>BORN AFTER the death of the BIOLOGICAL FATHER</strong>.</p><p><strong>Legal recognition:</strong></p><ul><li>In inheritance and succession (Hindu Succession Act, Indian Succession Act)</li><li>Must be CONCEIVED before father\'s death</li><li>If born within 9 months (280 days) of father\'s death → presumed legitimate</li><li>DNA may be required to prove paternity</li></ul><p>★ <strong>NEET-PG 2018 Q2 + NEET-PG 2024 Q1</strong> (verbatim): "Child delivered after death of biological father" = posthumous child.</p>', tags: ['PYQ 2018 Q2 + 2024 Q1'] },
  'presumption-death': { label: '7-Year Presumption of Death', info: '<p><strong>BSA § 110 (≡ IEA § 108):</strong></p><p>"When the question is whether a man is alive or dead, and it is proved that he has not been heard of for SEVEN YEARS by those who would naturally have heard of him if he had been alive, the burden of proving that he is alive is shifted to the person who affirms it."</p><p>★ Court therefore PRESUMES the person is DEAD after 7 years of unexplained absence.</p><p><strong>Applies for:</strong></p><ul><li>Inheritance, succession</li><li>Insurance claims</li><li>Re-marriage of spouse</li><li>Property settlement</li></ul><p>★ <strong>NEET-PG 2016 Q10</strong> verbatim — Person declared dead if not found for 7 years.</p>', tags: ['PYQ 2016 Q10', 'BSA 110 = IEA 108'] },
  'other-secondary': { label: 'Other Secondary Identifiers', info: '<ul><li><strong>Cheiloscopy</strong> — lip prints (Tsuchihashi classification: 6 types)</li><li><strong>Palatal rugoscopy</strong> — palatine rugae individual + permanent</li><li><strong>Frontal sinus radiographs</strong> — pattern is individual</li><li><strong>Ear morphology</strong> — helix, lobule pattern</li><li><strong>Footprints + foot-length-to-height ratio</strong></li><li><strong>Handwriting</strong> — slant, pressure, formation</li><li><strong>Voice analysis</strong> — spectrographic identification</li><li><strong>Iris recognition</strong> — biometric ID</li><li><strong>Gait analysis</strong> — CCTV-based walking pattern</li></ul>', tags: ['Cheiloscopy · palatal rugae · ear'] }
};

function nodeList(ids) { return ids.map(id => ({ nodeId: id, ...NODES[id] })); }

const MCQS = {
  'ID-01': [
    { stem: 'Locard is famous for:', options: ['Theory of exchange','Fingerprint study','Formula for estimation of stature','System of personal identification using body measurement'], answerIdx: 0, explain: 'Edmond Locard proposed the "exchange principle" — every contact leaves a trace. Foundation of trace evidence forensics. NEET-PG 2018 Q6 verbatim.', tag: '[NEET-PG 2018]' },
    { stem: 'Corpus delicti in homicide cases requires:', options: ['Body of victim only','Body + criminal act proof','Confession of accused','Witnesses only'], answerIdx: 1, explain: 'Corpus delicti = body / essence of crime — needs (1) identification of dead body AND (2) conclusive evidence of criminal act causing death.', tag: '[PG-Inspired]' },
    { stem: 'In a medicolegal case, the minimum number of identification marks a doctor should record is:', options: ['1','2','3','5'], answerIdx: 1, explain: 'At least 2 identification marks should be recorded in every MLC certificate. They should be permanent, easily noticeable features (scars, moles, tattoos).', tag: '[PG-Inspired]' }
  ],
  'ID-02': [
    { stem: 'Which of the following is NOT a PRIMARY identifier per Interpol DVI?', options: ['Fingerprints','Dental records','DNA profile','Visual recognition'], answerIdx: 3, explain: 'Primary identifiers (Interpol DVI) = fingerprint, dental records, DNA. Visual recognition, personal effects, tattoos are SECONDARY (unreliable in disasters).', tag: '[PG-Inspired]' },
    { stem: 'For a heavily decomposed/charred body, the MOST reliable identification method is:', options: ['Visual recognition','Personal effects','DNA from femur bone marrow / teeth','Anthropometry'], answerIdx: 2, explain: 'DNA from femur bone marrow and dental pulp (especially petrous temporal bone) is most reliable for charred/decomposed bodies. Visual unreliable, effects can be stolen.', tag: '[PG-Inspired]' },
    { stem: 'The technique of overlaying antemortem photo on skull for identification is called:', options: ['Anthropometry','Superimposition','Cheiloscopy','Dactyloscopy'], answerIdx: 1, explain: 'Superimposition — AM photograph overlaid on skull; if anatomical landmarks align → identification confirmed. Famously used in Indira Gandhi assassination case.', tag: '[PG-Inspired]' }
  ],
  'ID-03': [
    { stem: 'The sub-pubic angle in an adult female is approximately:', options: ['&lt; 65°','65-75°','85°','110-120°'], answerIdx: 2, explain: 'Female sub-pubic angle = 85° (typically &gt; 90°, range 85-100°). Male sub-pubic angle &lt; 90° (50-60°). NEET-PG 2016 Q14 verbatim.', tag: '[NEET-PG 2016]' },
    { stem: 'Barr bodies in females are seen in cells of:', options: ['Buccal mucosa','Skin','Amniotic fluid','All of the above'], answerIdx: 3, explain: 'Barr bodies (inactivated X chromosome) found in somatic cells — buccal smear (commonest), skin, cartilage, nerve, amniotic fluid. Females = "chromatin positive".', tag: '[PG-Inspired]' },
    { stem: 'A "drumstick" appendage on neutrophil nucleus, indicative of female sex, is called:', options: ['Barr body','Davidson body','Howell-Jolly body','Auer rod'], answerIdx: 1, explain: 'Davidson body = additional lobe (drumstick) on female neutrophil nucleus, 1.5 µm. Need ≥ 6% count on peripheral smear to confirm female.', tag: '[PG-Inspired]' },
    { stem: 'The most reliable single bone for sex determination from skeletal remains is:', options: ['Skull','Pelvis','Femur','Sternum'], answerIdx: 1, explain: 'Pelvis is most reliable (~95% accuracy) — sub-pubic angle, sciatic notch, brim shape. Skull alone ~92%. Combined pelvis+skull ~98%.', tag: '[PG-Inspired]' }
  ],
  'ID-04': [
    { stem: 'A person is declared dead if he/she is not heard of for:', options: ['7 years','10 years','14 years','21 years'], answerIdx: 0, explain: 'BSA §110 (≡ IEA §108) — person presumed dead if not heard of for 7 years. Burden shifts to anyone claiming they are alive. NEET-PG 2016 Q10 verbatim.', tag: '[NEET-PG 2016]' },
    { stem: 'Per IPC 82 (BNS equivalent), no criminal responsibility applies below age:', options: ['5 yr','7 yr','12 yr','16 yr'], answerIdx: 1, explain: 'IPC 82 — child &lt; 7 yr CANNOT be held criminally responsible (doli incapax absolute). 7-12 yr — qualified responsibility based on maturity (IPC 83).', tag: '[PG-Inspired]' },
    { stem: 'Tanner stage 5 represents:', options: ['Prepubertal','Early puberty','Mid puberty','Adult sexual maturity'], answerIdx: 3, explain: 'Tanner staging (sexual maturity rating): T1 prepubertal → T2-T4 progressive → T5 adult genitalia, breast, pubic hair.', tag: '[PG-Inspired]' }
  ],
  'ID-05': [
    { stem: 'First incisor to erupt is:', options: ['Lower central','Upper central','Lower lateral','Upper lateral'], answerIdx: 0, explain: 'Lower central incisor is the first tooth to erupt at 6-8 months. NEET-PG 2016 Q15 verbatim.', tag: '[NEET-PG 2016]' },
    { stem: 'A baby has started to get his first milk teeth. His age is approximately:', options: ['3 months','6 months','9 months','12 months'], answerIdx: 1, explain: 'First milk tooth (lower central incisor) erupts at 6 months. NEET-PG 2016 Q16 verbatim. Half-year rule: incisor 6 mo → 1st molar 1 yr → canine 1.5 yr → 2nd molar 2 yr.', tag: '[NEET-PG 2016]' },
    { stem: 'Total number of primary teeth in a human is:', options: ['20','24','28','32'], answerIdx: 0, explain: '20 primary (milk/deciduous) teeth = 8 incisors + 4 canines + 8 molars (no premolars in primary set). Permanent = 32 (8I + 4C + 8PM + 12M).', tag: '[PG-Inspired]' },
    { stem: 'Primary molars are replaced by:', options: ['Permanent molars','Permanent premolars','Permanent canines','Nothing'], answerIdx: 1, explain: 'Primary molars → permanent PREMOLARS (not molars). Primary incisors/canines → permanent incisors/canines. Permanent molars erupt BEHIND primary molars (no primary tooth lost).', tag: '[PG-Inspired]' },
    { stem: 'In Gustafson\'s method, the SINGLE most important parameter is:', options: ['Attrition','Periodontosis','Secondary dentine','Root transparency'], answerIdx: 3, explain: 'Of the 6 Gustafson parameters (A, P, S, R, C, T), ROOT TRANSPARENCY (T) is the single most important indicator of age in adults.', tag: '[PG-Inspired]' }
  ],
  'ID-06': [
    { stem: 'Ossification centre of scaphoid appears at:', options: ['1-6 months','1-2 years','2-4 years','4-7 years'], answerIdx: 3, explain: 'Scaphoid ossification appears at 4-7 years (≈ 4-6 yr female, 7 yr male). NEET-PG 2016 Q13 verbatim. Carpal sequence: Capitate → Hamate → Triquetral → Lunate → Trapezium → Trapezoid → Scaphoid → PISIFORM (9-12 yr, last).', tag: '[NEET-PG 2016]' },
    { stem: 'The LAST carpal bone to ossify is:', options: ['Scaphoid','Lunate','Pisiform','Capitate'], answerIdx: 2, explain: 'Pisiform (sesamoid bone) is the LAST carpal to ossify at 9-12 years. It is unique — embedded in flexor carpi ulnaris tendon.', tag: '[PG-Inspired]' },
    { stem: 'Which 3 tarsal bones are present at birth (proves full-term foetus)?', options: ['Calcaneum, Talus, Cuboid','Talus, Navicular, Cuneiform','Calcaneum, Cuneiform, Cuboid','Talus, Cuboid, Cuneiform'], answerIdx: 0, explain: 'Calcaneum (3 mo IUL), Talus (6-7 mo IUL), and Cuboid (9 mo IUL) ossify in utero → presence proves near-term/full-term foetus. Important in infanticide cases.', tag: '[PG-Inspired]' },
    { stem: 'The LAST major bone to fuse in the human skeleton is the:', options: ['Femur head','Distal radius','Medial end of clavicle','Iliac crest'], answerIdx: 2, explain: 'Medial end of clavicle fuses at 20-22 years — LAST major epiphysis to fuse. Important landmark for distinguishing adolescents from young adults.', tag: '[PG-Inspired]' },
    { stem: 'Ossification of distal end of femur occurs:', options: ['At birth','Shortly before birth (in utero)','1 year','3 years'], answerIdx: 1, explain: 'Distal femoral epiphysis ossifies BEFORE birth (~ 36 weeks IUL). Its presence on infant X-ray indicates FULL-TERM foetus — important in alleged stillbirth / infanticide cases.', tag: '[PG-Inspired]' }
  ],
  'ID-07': [
    { stem: 'The most reliable single long bone for stature estimation is:', options: ['Tibia','Humerus','Femur','Radius'], answerIdx: 2, explain: 'Femur is the longest and most reliable single bone. Trotter-Gleser and Pearson regressions all give highest accuracy with femur. Combined long bones give even better estimate.', tag: '[PG-Inspired]' },
    { stem: 'Stature ≈ how many × foot length (rough estimate)?', options: ['4','5','6','7'], answerIdx: 2, explain: 'Stature ≈ 6 × foot length (varies by population). Useful field rule for crime scene with bare footprint.', tag: '[UNIV]' },
    { stem: 'After 25 years of age, stature DECREASES at approximately:', options: ['1 mm per year','1 cm per year','5 mm per year','10 mm per year'], answerIdx: 0, explain: 'After 25 yr → stature decreases ~ 1 mm/year due to intervertebral disc dehydration, kyphosis, vertebral compression.', tag: '[PG-Inspired]' },
    { stem: 'Karl Pearson (1899) gave regression formulae for stature using:', options: ['Hand only','Long bones (femur, tibia, humerus, radius)','Cranial measurements','Foot only'], answerIdx: 1, explain: 'Karl Pearson 1899 — regression equations from long bones (especially femur, tibia, humerus, radius). Trotter-Gleser 1952 improved them with race+sex specificity.', tag: '[UNIV]' }
  ],
  'ID-08': [
    { stem: 'Which race typically has a TRIANGULAR hard palate?', options: ['Caucasoid','Mongoloid','Negroid','None'], answerIdx: 0, explain: 'Caucasoid → triangular hard palate · Mongoloid → large flattened palate · Negroid → rectangular palate.', tag: '[PG-Inspired]' },
    { stem: 'Brachycephalic skull (cephalic index &gt; 80) is characteristic of:', options: ['Caucasoid','Mongoloid','Negroid','Australoid'], answerIdx: 1, explain: 'Brachycephalic (round-headed) → Mongoloid. Dolichocephalic (long-headed, &lt; 75) → Caucasoid, Negroid. Mesocephalic (75-80) → many Europeans, Indians.', tag: '[PG-Inspired]' },
    { stem: 'Cephalic index is calculated as:', options: ['(Length / breadth) × 100','(Breadth / length) × 100','(Height / breadth) × 100','(Length × breadth) / 100'], answerIdx: 1, explain: 'Cephalic index = (max breadth / max length of skull) × 100. Dolicho &lt; 75 · Meso 75-80 · Brachy &gt; 80.', tag: '[PG-Inspired]' }
  ],
  'ID-09': [
    { stem: 'Two identical (monozygotic) twins will NOT have same:', options: ['Fingerprints','DNA','Iris color','Blood group'], answerIdx: 0, explain: 'Monozygotic twins share DNA (almost identical), blood group, iris color — but FINGERPRINTS differ. Fingerprints are influenced by IUL environment + epigenetics. NEET-PG 2019 Q5 verbatim.', tag: '[NEET-PG 2019]' },
    { stem: 'The commonest fingerprint pattern is:', options: ['Arch (7%)','Loop (65%)','Whorl (25%)','Composite (2-3%)'], answerIdx: 1, explain: 'Loop = 65% (commonest) · Whorl 25% · Arch 7% · Composite 2-3%. Mnemonic: "Loops Wear Aprons Carelessly".', tag: '[PG-Inspired]' },
    { stem: 'Fingerprints are formed during intra-uterine life by:', options: ['3 weeks','3 months','7 months','9 months'], answerIdx: 1, explain: 'Primary epidermal ridges appear at 2-3 month IUL; secondary by 5th month; fully formed by 24 weeks IUL. Permanent thereafter.', tag: '[PG-Inspired]' },
    { stem: 'For positive identification by fingerprint, the standard number of matching points required is:', options: ['8-10','12-15','16-20','30-40'], answerIdx: 2, explain: '16-20 matching points = positive identification (Indian forensic standard). Compare ridge endings, delta, core, fork, island, ridge count.', tag: '[PG-Inspired]' },
    { stem: 'Fingerprints made visible by ninhydrin development are:', options: ['Visible prints','Plastic prints','Latent prints','Chance prints'], answerIdx: 2, explain: 'Latent prints (invisible, from sweat + sebum) need REAGENTS — ninhydrin (purple, amino acids), cyanoacrylate fuming, silver nitrate, powders.', tag: '[PG-Inspired]' }
  ],
  'ID-10': [
    { stem: 'A faded/invisible tattoo can be best revealed by examining the:', options: ['Skin surface only','Regional LYMPH NODE','Spectrophotometer','Ordinary light'], answerIdx: 1, explain: 'Examine REGIONAL LYMPH NODE — pigment from tattoo drains to local nodes and is deposited. Histology of node shows pigment. NEET-PG 2020 Q3 verbatim.', tag: '[NEET-PG 2020]' },
    { stem: 'A child born 8 months after the death of the presumed father, DNA confirms biological relation. The child is termed:', options: ['Suppositious child','Fabricated child','Posthumous child','Illegitimate child'], answerIdx: 2, explain: 'Posthumous child = born AFTER death of biological father. Conceived before death; born within 9 months. NEET-PG 2024 Q1 verbatim.', tag: '[NEET-PG 2024]' },
    { stem: 'The Bertillon system of identification was based on:', options: ['Fingerprints','DNA','Body measurements (anthropometry)','Dentition'], answerIdx: 2, explain: 'Bertillon system (1879) = anthropometry — body measurements (height, head, ear, foot) + descriptive data + body marks. Replaced by fingerprints due to subjective error.', tag: '[PG-Inspired]' },
    { stem: 'A scar from an incised wound is:', options: ['Linear','Irregular and broad','Round and depressed','Spotted'], answerIdx: 0, explain: 'Scar assumes shape of wound: Incised → linear · Lacerated → irregular broad · Stab → oval/elliptical · Burn → irregular coarse · Bullet → round depressed.', tag: '[PG-Inspired]' },
    { stem: 'Striae gravidarum scars are an identification marker of:', options: ['Past trauma','Past pregnancy','Past sexual assault','Skin disease'], answerIdx: 1, explain: 'Striae gravidarum = multiple scars over abdomen in females who are or were pregnant. Useful identification marker for past pregnancy.', tag: '[PG-Inspired]' }
  ]
};

